_SORT_TABLE_JS = """
<script>
function sortTable(tableId, col, numeric) {
    var table = document.getElementById(tableId);
    var tbody = table.querySelector('tbody');
    var rows = Array.from(tbody.querySelectorAll('tr'));
    var asc = (table.dataset.sortCol == col && table.dataset.sortDir == 'asc') ? false : true;
    table.dataset.sortCol = col;
    table.dataset.sortDir = asc ? 'asc' : 'desc';
    rows.sort(function(a, b) {
        var aVal = a.cells[col] ? a.cells[col].textContent.trim() : '';
        var bVal = b.cells[col] ? b.cells[col].textContent.trim() : '';
        if (numeric) { aVal = parseFloat(aVal) || 0; bVal = parseFloat(bVal) || 0; }
        if (aVal < bVal) return asc ? -1 : 1;
        if (aVal > bVal) return asc ? 1 : -1;
        return 0;
    });
    rows.forEach(function(row) { tbody.appendChild(row); });
    // Update sort arrow on all th
    Array.from(table.querySelectorAll('thead th')).forEach(function(th, i) {
        th.textContent = th.textContent.replace(/ [↑↓↕]$/, '');
        if (i == col) th.textContent += asc ? ' ↑' : ' ↓';
        else th.textContent += ' ↕';
    });
}
</script>
<style>
.sortable-th { cursor: pointer; user-select: none; }
.sortable-th:hover { color: #f093fb; }
</style>
"""


def generate_team_report():
    """チーム構成分析レポート."""
    print("  Generating Team Composition Report...")
    teams = load_json("teams.json")
    if not teams:
        return

    high_score_teams = teams.get("high_score_teams", [])
    role_combos = teams.get("role_combinations", [])
    rec_pairs = teams.get("recommended_pairs", [])
    size_stats = teams.get("team_size_stats", {})

    body = _SORT_TABLE_JS

    # Summary stats
    body += '<div class="card">'
    body += "<h2>Team Analysis Summary</h2>"
    body += '<div class="stats-grid">'
    for label, val in [
        ("High-Score Works", fmt_num(teams.get("total_high_score", 0))),
        ("Top 50 Teams Listed", fmt_num(len(high_score_teams))),
        ("Role Combinations", fmt_num(len(role_combos))),
        ("Recommended Pairs", fmt_num(len(rec_pairs))),
        ("Min Team Size", fmt_num(size_stats.get("min", 0))),
        ("Max Team Size", fmt_num(size_stats.get("max", 0))),
        ("Avg Team Size", f"{size_stats.get('avg', 0):.1f}"),
        ("High-Score Avg Size", f"{size_stats.get('high_score_avg', 0):.1f}"),
    ]:
        body += f'<div class="stat-card"><div class="value">{val}</div><div class="label">{label}</div></div>'
    body += "</div></div>"

    def _th(label: str, col: int, numeric: bool, table_id: str) -> str:
        num_str = "true" if numeric else "false"
        return (
            f'<th class="sortable-th" onclick="sortTable(\'{table_id}\', {col}, {num_str})">'
            f"{label} ↕</th>"
        )

    # --- Top 50 Teams (by team size, sortable) ---
    body += '<div class="card">'
    body += "<h2>Top 50 チーム（チームサイズ順 — 列ヘッダーでソート可）</h2>"
    body += section_desc("列ヘッダーをクリックすると昇順/降順で並べ替えできます。")
    body += f'<table id="team-table-raw"><thead><tr>'
    for col_i, (label, numeric) in enumerate([
        ("#", False), ("タイトル", False), ("年", True),
        ("チームサイズ", True), ("コアロール数", True),
    ]):
        body += _th(label, col_i, numeric, "team-table-raw")
    body += "</tr></thead><tbody>"
    for i, team in enumerate(high_score_teams[:50], 1):
        title = team.get("title", team.get("anime_id", ""))
        body += f"<tr><td>{i}</td><td>{title}</td><td>{team.get('year', '')}</td>"
        body += f"<td>{team.get('team_size', 0)}</td><td>{team.get('core_roles', 0)}</td></tr>"
    body += "</tbody></table></div>"

    # Removed: 年別偏差値テーブル, 偏差値Violin, 偏差値×年散布図, Team Size vs Anime Score,
    # Role Diversity vs Anime Score — all derived from anime.score (viewer ratings)

    # Team size vs core roles scatter (structural metrics only)
    if high_score_teams:
        diversity_data = [t for t in high_score_teams if t.get("core_roles", 0) > 0]
        if diversity_data:
            fig_struct = go.Figure(go.Scatter(
                x=[t.get("team_size", 0) for t in diversity_data],
                y=[t.get("core_roles", 0) for t in diversity_data],
                mode="markers",
                marker=dict(
                    size=10,
                    color=[t.get("year", 2020) for t in diversity_data],
                    colorscale="Viridis", showscale=True,
                    colorbar=dict(title="Year"),
                    opacity=0.7,
                ),
                text=[t.get("title", "") for t in diversity_data],
                hovertemplate="%{text}<br>Team Size: %{x}<br>Core Roles: %{y}<br>Year: %{marker.color}<extra></extra>",
            ))
            fig_struct.update_layout(
                title="チーム規模 vs ロール多様性",
                xaxis_title="チームサイズ（スタッフ数）",
                yaxis_title="コアロール数",
            )
            body += '<div class="card">'
            body += "<h2>チーム規模 vs ロール多様性</h2>"
            body += chart_guide(
                "X=チーム規模（スタッフ数）、Y=ユニークなコアロール数、色=放送年。"
                "チーム規模が大きいほどロール多様性が高いか、"
                "小規模でも多様なロールを持つ効率的なチームがあるかを確認できます。"
            )
            body += plotly_div_safe(fig_struct, "team_struct_scatter", 500)
            body += "</div>"

    # Role combinations
    if role_combos:
        fig = go.Figure(go.Bar(
            x=[rc["roles"] for rc in role_combos[:20]],
            y=[rc["count"] for rc in role_combos[:20]],
            marker_color="#a0d2db",
            hovertemplate="%{x}: %{y}<extra></extra>",
        ))
        fig.update_layout(title="Top 20 Role Combinations in High-Score Works", xaxis_tickangle=-45)

        body += '<div class="card">'
        body += "<h2>Role Combinations</h2>"
        body += chart_guide(
            "高評価作品に頻出する役職の組み合わせを棒グラフで表示。"
            "どのスタッフ構成が高品質アニメを生み出しやすいかのパターンが分かります。"
        )
        body += plotly_div_safe(fig, "role_combos", 450)
        body += "</div>"

    # Recommended pairs
    if rec_pairs:
        body += '<div class="card">'
        body += "<h2>Top 30 Recommended Collaboration Pairs</h2>"
        body += section_desc(
            "高評価作品で繰り返し共同クレジットされた人物ペア。"
            "共有数が多いほど、創造的相乗効果が高いことを示唆します。"
        )
        body += "<table><thead><tr>"
        body += "<th>#</th><th>Person A</th><th>Person B</th><th>Shared High-Score Works</th>"
        body += "</tr></thead><tbody>"
        for i, pair in enumerate(rec_pairs[:30], 1):
            name_a = pair.get("name_a") or pair["person_a"]
            name_b = pair.get("name_b") or pair["person_b"]
            body += f"<tr><td>{i}</td><td>{person_link(name_a, pair['person_a'])}</td><td>{person_link(name_b, pair['person_b'])}</td>"
            body += f'<td><span class="badge badge-high">{pair["shared_high_score_works"]}</span></td></tr>'
        body += "</tbody></table></div>"

    # Year distribution of high-score works
    if high_score_teams:
        year_counts = Counter(t.get("year", 0) for t in high_score_teams if t.get("year"))
        years_sorted = sorted(year_counts.keys())
        fig = go.Figure(go.Bar(
            x=years_sorted, y=[year_counts[y] for y in years_sorted],
            marker_color="#f093fb",
            hovertemplate="%{x}: %{y} works<extra></extra>",
        ))
        fig.update_layout(title="High-Score Works by Year", xaxis_title="Year", yaxis_title="Count")
        body += '<div class="card">'
        body += "<h2>High-Score Works Timeline</h2>"
        body += plotly_div_safe(fig, "team_years", 400)
        body += "</div>"

    # Data-driven key findings
    high_score_count = teams.get("total_high_score", 0)
    avg_size = size_stats.get("avg", 0)
    hs_avg_size = size_stats.get("high_score_avg", 0)
    body += key_findings([
        f"分析対象 {fmt_num(high_score_count)} 本の高評価作品において、"
        f"平均チームサイズ {avg_size:.1f} 人（全体）に対して高評価作品は {hs_avg_size:.1f} 人と"
        "{'大きい' if hs_avg_size > avg_size else '同程度'}",
        f"頻出役職組み合わせ {fmt_num(len(role_combos))} パターンが特定され、成功作品に共通するスタッフ構成がある",
        f"繰り返し共演するコラボペアが {fmt_num(len(rec_pairs))} 組確認され、安定した品質を生み出す傾向",
    ])

    body += significance_section("成功チームの構成要素を解明", [
        "アニメ制作の品質はチームダイナミクスに大きく依存しますが、「どの役職の組み合わせが"
        "高品質作品を生み出すか」はこれまで経験則に頼るしかありませんでした。"
        "本分析は高評価作品のスタッフ構成をデータで特定し、制作投資の効率化根拠を提供します。",
        "「この人とこの人が組むと成功しやすい」という推薦ペアは、感覚的なキャスティングを"
        "実績データに基づく意思決定に変えます。特にシリーズ続編や類似ジャンルの新作で有効です。",
    ])
    body += utilization_guide([
        {"role": "制作プロデューサー", "how": "Role Combinationsチャートで自プロジェクトのジャンルに対応する上位役職組み合わせを確認し、その構成を充足させるようにスタッフィングリストを組む"},
        {"role": "制作デスク", "how": "Top 30 Recommended Pairsテーブルで自スタジオに在籍する人物ペアを探し、実績ある組み合わせを同一作品の担当割り当てに優先する"},
        {"role": "スタジオ経営者", "how": "High-Score Works Timelineで自社の高評価作品が多い年を特定し、その年のチーム規模・役職構成を次期作品の採用計画の雛形として使う"},
        {"role": "アニメーター", "how": "自身が頻繁に共演するパートナーのクレジット歴とスコアを確認し、共演実績の強さをポートフォリオに「実績のあるコラボ」として記載する"},
    ])
    body += future_possibilities([
        "役職ごとの「予算帯別最適チームサイズ」の精緻化（低予算・中規模・大作別のサブ分析）",
        "過去の成功チームを類似度検索できる「チーム事例ライブラリ」（類似プロジェクトの参照チームを自動提案）",
        "高評価チームの再結集プランニング（同じチームで続編を作る場合の最大効果スケジュール）",
        "スタッフ可用性・契約状況と実績を組み合わせた「実行可能な最適チーム」の自動候補提示",
    ])

    html = wrap_html(
        "チーム構成分析",
        f"チーム構成パターン分析 — {fmt_num(teams.get('total_high_score', 0))}本の高評価作品を分析",
        body,
        intro_html=report_intro(
            "チーム構成分析",
            "どのようなチーム構成が優れたアニメを生み出すのか？ 本レポートでは高評価作品の"
            "スタッフ構成を分析し、最適なチーム規模・成功しやすい役職組み合わせ・"
            "実績のあるコラボレーションペアを明らかにします。",
            "プロデューサー、制作デスク、制作進行",
        ),
        glossary_terms={
            **COMMON_GLOSSARY_TERMS,
            "高評価作品 (High-Score Work)": "平均以上の視聴者/評論家スコアを持つアニメ作品。",
            "コアロール (Core Roles)": (
                "監督・作画監督・キャラクターデザインなど、作品に配置された"
                "主要制作役職の種類数。"
            ),
        },
    )
    out = REPORTS_DIR / "team_analysis.html"
    out.write_text(html, encoding="utf-8")
    print(f"    -> {out}")


# ============================================================
# Report 4: Career Transitions
# ============================================================

def generate_career_report():
    """キャリア遷移レポート."""
    print("  Generating Career Transitions Report...")
    transitions = load_json("transitions.json")
    role_flow = load_json("role_flow.json")

    if not transitions and not role_flow:
        return

    body = ""

    if transitions:
        trans = transitions.get("transitions", [])
        paths = transitions.get("career_paths", [])
        avg_time = transitions.get("avg_time_to_stage", {})
        total_analyzed = transitions.get("total_persons_analyzed", 0)

        # Summary
        body += '<div class="card">'
        body += "<h2>Career Transition Analysis</h2>"
        body += '<div class="stats-grid">'
        for label, val in [
            ("Persons Analyzed", fmt_num(total_analyzed)),
            ("Transition Types", fmt_num(len(trans))),
            ("Career Paths", fmt_num(len(paths))),
            ("Career Stages", fmt_num(len(avg_time))),
        ]:
            body += f'<div class="stat-card"><div class="value">{val}</div><div class="label">{label}</div></div>'
        body += "</div></div>"

        # Transition matrix
        if trans:
            stages = sorted(set(
                [t["from_label"] for t in trans] + [t["to_label"] for t in trans]
            ))
            matrix = {}
            for t in trans:
                matrix[(t["from_label"], t["to_label"])] = t["count"]

            z = [[matrix.get((s1, s2), 0) for s2 in stages] for s1 in stages]

            fig = go.Figure(go.Heatmap(
                z=z, x=stages, y=stages,
                colorscale="Magma", text=[[str(v) if v > 0 else "" for v in row] for row in z],
                texttemplate="%{text}", hovertemplate="%{y} -> %{x}: %{z}<extra></extra>",
            ))
            fig.update_layout(title="Career Stage Transition Matrix", xaxis_title="To Stage", yaxis_title="From Stage")

            body += '<div class="card">'
            body += "<h2>Transition Matrix</h2>"
            body += chart_guide(
                "行=出発ステージ、列=到達ステージ。明るいセルほど遷移が頻繁であることを示します。"
                "行を横に読むと、そのステージの人々が次にどこへ進むかが分かります。"
            )
            body += plotly_div_safe(fig, "transition_matrix", 500)
            body += "</div>"

            # Transition probability heatmap
            z_prob = []
            for row in z:
                row_total = sum(row)
                if row_total > 0:
                    z_prob.append([v / row_total * 100 for v in row])
                else:
                    z_prob.append([0.0] * len(row))

            fig_prob = go.Figure(go.Heatmap(
                z=z_prob, x=stages, y=stages,
                colorscale="Viridis",
                texttemplate="%{z:.1f}%",
                hovertemplate="%{y} → %{x}: %{z:.1f}%<extra></extra>",
            ))
            fig_prob.update_layout(
                title="キャリアステージ遷移確率行列",
                xaxis_title="遷移先ステージ",
                yaxis_title="遷移元ステージ",
            )
            body += '<div class="card">'
            body += "<h2>遷移確率行列</h2>"
            body += chart_guide(
                "各行を合計100%に正規化した確率ベースの遷移行列。"
                "「ステージXの人がステージYに移行する確率」を直接読み取れます。"
                "対角線の値が高い＝そのステージに留まる傾向、右上が高い＝昇進率が高い。"
            )
            body += plotly_div_safe(fig_prob, "transition_prob", 500)
            body += "</div>"

        # ── Role-to-Role Transition Times (因果チェーン) ──
        if trans:
            # Build consecutive stage transitions (from_stage → to_stage where to > from)
            consecutive = [t for t in trans if t["to_stage"] > t["from_stage"]]
            if consecutive:
                # Sort by from_stage for natural chain order
                consecutive.sort(key=lambda t: (t["from_stage"], t["to_stage"]))
                fig_chain = go.Figure()
                labels_chain = []
                years_chain = []
                counts_chain = []
                for t in consecutive:
                    label = f"{t['from_label']} → {t['to_label']}"
                    labels_chain.append(label)
                    years_chain.append(t.get("avg_years", 0))
                    counts_chain.append(t.get("count", 0))
                fig_chain.add_trace(go.Bar(
                    y=labels_chain, x=years_chain, orientation="h",
                    marker_color="#f093fb",
                    text=[f"{y:.1f}年 (n={c:,})" for y, c in zip(years_chain, counts_chain)],
                    textposition="auto",
                    hovertemplate="%{y}<br>平均遷移時間: %{x:.1f}年<extra></extra>",
                ))
                fig_chain.update_layout(
                    title="ロール間遷移時間（前ステージからの年数）",
                    xaxis_title="平均遷移年数",
                    yaxis_title="遷移パス",
                    height=max(400, len(labels_chain) * 40),
                )
                body += '<div class="card">'
                body += "<h2>ロール間遷移時間（因果チェーン）</h2>"
                body += chart_guide(
                    "各バーは「前のステージから次のステージまでの平均年数」を示します。"
                    "例: 動画→原画が4.5年なら、動画マンが原画マンになるまで平均4.5年。"
                    "「デビューからの累積年数」ではなく「ステージ間の遷移時間」であるため、"
                    "因果的な解釈（何年かければ次に進めるか）に適しています。"
                )
                body += plotly_div_safe(fig_chain, "role_chain_times", max(400, len(labels_chain) * 40))
                body += competing_interpretations(
                    "動画→原画の平均4.5年は「原画に必要な修業期間」を反映する",
                    [
                        "生存バイアス: 原画に昇進した人のみが観測され、昇進しなかった人の期間は含まれない",
                        "選択効果: 才能ある人は早く昇進し、平均年数は「遅咲き組」に引きずられている可能性",
                        "時代効果: 1990年代と2020年代では業界構造が異なり、遷移時間も異なるはず",
                    ],
                )
                body += "</div>"

        # Average time to each stage — Ridge Plot (デビューからの累積年数)
        if avg_time:
            body += caveat_box(
                "以下の「到達年数」はデビューからの累積年数であり、前ステージからの遷移時間ではありません。"
                "因果的な解釈（特定のステージに到達するのに何年かかるか）には上の「ロール間遷移時間」を参照してください。"
                "累積年数にはステージをスキップした人や長期間同じステージに留まった人の影響が混在しています。"
            )
            stage_labels_t = []
            avg_years = []
            median_years = []
            sample_sizes = []
            for stage_id in sorted(avg_time.keys(), key=int):
                sd = avg_time[stage_id]
                stage_labels_t.append(sd.get("label", f"Stage {stage_id}"))
                avg_years.append(sd.get("avg_years", 0))
                median_years.append(sd.get("median_years", 0))
                sample_sizes.append(sd.get("sample_size", 0))

            # Ridge plot: time to stage distribution (simulated from mean/median/n)
            # Use scores.json for actual per-person data if available
            scores_for_ridge = get_feat_person_scores()
            stage_time_groups: dict[str, list[float]] = {}
            if scores_for_ridge:
                for p in scores_for_ridge:
                    career = p.get("career", {})
                    hs = career.get("highest_stage", 0)
                    ay = career.get("active_years", 0)
                    if hs > 0 and ay > 0:
                        label = stage_labels_t[min(hs, len(stage_labels_t) - 1)] if hs < len(stage_labels_t) else f"Stage {hs}"
                        stage_time_groups.setdefault(label, []).append(float(ay))

            if stage_time_groups:
                fig_ridge = ridge_plot(
                    stage_time_groups,
                    title="ステージ別 到達年数分布 (Ridge Plot)",
                    xlabel="活動年数",
                    height=max(400, len(stage_time_groups) * 70),
                )
                body += '<div class="card">'
                body += "<h2>Time to Stage (Ridge Plot)</h2>"
                body += chart_guide(
                    "各ステージの到達年数分布をKDEで重ねて比較。"
                    "bimodal（二山）分布は「早期昇進組」と「遅咲き組」の存在を示す。"
                    "白線=中央値。分布の形状でキャリア進行の多様性を読み取れる。"
                )
                body += plotly_div_safe(fig_ridge, "time_to_stage_ridge", max(400, len(stage_time_groups) * 70))
                body += "</div>"
            else:
                # Fallback: bar chart
                fig = go.Figure()
                fig.add_trace(go.Bar(
                    x=stage_labels_t, y=avg_years, name="Average",
                    marker_color="#f093fb",
                ))
                fig.add_trace(go.Bar(
                    x=stage_labels_t, y=median_years, name="Median",
                    marker_color="#a0d2db",
                ))
                fig.update_layout(title="Average Time to Reach Each Career Stage", barmode="group",
                                xaxis_title="Career Stage", yaxis_title="Years")
                body += '<div class="card">'
                body += "<h2>Time to Stage</h2>"
                body += plotly_div_safe(fig, "time_to_stage", 400)
                body += "</div>"

            # Summary Table
            body += '<div class="card">'
            body += "<table><thead><tr><th>Stage</th><th>Avg Years</th><th>Median Years</th><th>Sample Size</th></tr></thead><tbody>"
            for lbl, avg, med, sz in zip(stage_labels_t, avg_years, median_years, sample_sizes):
                body += f"<tr><td>{lbl}</td><td>{avg:.1f}</td><td>{med:.0f}</td><td>{fmt_num(sz)}</td></tr>"
            body += "</tbody></table></div>"

        # Top career paths
        if paths:
            path_labels_top = [" → ".join(p["path_labels"]) for p in paths[:15]]
            path_counts_top = [p["count"] for p in paths[:15]]
            fig = go.Figure(go.Bar(
                y=path_labels_top[::-1],
                x=path_counts_top[::-1],
                orientation="h",
                marker_color="#fda085",
                hovertemplate="%{y}: %{x}<extra></extra>",
            ))
            fig.update_layout(
                title="Top 15 Career Paths",
                xaxis_title="人数",
                xaxis_type="log",
                yaxis_title="",
                height=max(400, len(path_labels_top) * 30),
            )

            body += '<div class="card">'
            body += "<h2>Most Common Career Paths</h2>"
            body += plotly_div_safe(fig, "career_paths", 450)
            body += "</div>"

    # Sankey diagram from role_flow
    if role_flow:
        nodes = role_flow.get("nodes", [])
        links = role_flow.get("links", [])

        if nodes and links:
            node_labels = [n["label"] for n in nodes]
            node_map = {n["id"]: i for i, n in enumerate(nodes)}

            # Filter to top transitions for readability
            sorted_links = sorted(links, key=lambda x: x["value"], reverse=True)[:40]

            valid = [lk for lk in sorted_links if lk["source"] in node_map and lk["target"] in node_map]
            src_indices = [node_map[lk["source"]] for lk in valid]
            tgt_indices = [node_map[lk["target"]] for lk in valid]
            values = [lk["value"] for lk in valid]

            node_colors = px.colors.qualitative.Pastel
            link_colors = []
            for s in src_indices:
                c = node_colors[s % len(node_colors)]
                # Convert rgb() to rgba() with transparency
                if c.startswith("rgb("):
                    link_colors.append(c.replace("rgb(", "rgba(").replace(")", ",0.3)"))
                else:
                    link_colors.append("rgba(180,180,200,0.3)")

            fig = go.Figure(go.Sankey(
                node=dict(
                    pad=15, thickness=20,
                    label=node_labels,
                    color=[node_colors[i % len(node_colors)] for i in range(len(node_labels))],
                ),
                link=dict(
                    source=src_indices, target=tgt_indices, value=values,
                    color=link_colors,
                ),
            ))
            fig.update_layout(title=f"Career Role Flow (Top 40 transitions, {fmt_num(role_flow.get('total_transitions', 0))} total)")

            body += '<div class="card">'
            body += "<h2>Role Flow (Sankey Diagram)</h2>"
            body += chart_guide(
                "サンキーダイアグラムは役職間のフローを表示します。帯が太いほど、"
                "その遷移を行う人数が多いことを意味します。左から右へ帯を追うと"
                "キャリアパスを辿れます。"
            )
            body += plotly_div_safe(fig, "sankey", 600)
            body += "</div>"

    # --- C3 Enhancement: 追加チャート ---

    # C3-1: ステージ別 中央値到達年数（横棒グラフ）
    if transitions and avg_time:
        avg_time = transitions.get("avg_time_to_stage", {})
        stage_labels_bar = []
        median_years_bar = []
        sample_sizes_bar = []
        stage_colors_bar = ["#f093fb", "#a0d2db", "#667eea", "#06D6A0",
                            "#FFD166", "#f5576c", "#F72585"]
        for stage_id in sorted(avg_time.keys(), key=int):
            sd = avg_time[stage_id]
            stage_labels_bar.append(sd.get("label", f"Stage {stage_id}"))
            median_years_bar.append(sd.get("median_years", 0))
            sample_sizes_bar.append(sd.get("sample_size", 0))
        if stage_labels_bar:
            fig_stage_bar = go.Figure(go.Bar(
                y=stage_labels_bar[::-1],
                x=median_years_bar[::-1],
                orientation="h",
                marker_color=stage_colors_bar[:len(stage_labels_bar)][::-1],
                text=[f"{v:.1f}年 (n={n})" for v, n in zip(median_years_bar[::-1], sample_sizes_bar[::-1])],
                textposition="outside",
                hovertemplate="%{y}: 中央値 %{x:.1f}年<extra></extra>",
            ))
            fig_stage_bar.update_layout(
                title="ステージ別 中央値到達年数",
                xaxis_title="中央値年数",
                height=max(350, len(stage_labels_bar) * 50),
            )
            body += '<div class="card"><h2>ステージ別 中央値到達年数</h2>'
            body += chart_guide("各ステージに到達するまでの中央値年数。棒が長いほど到達に時間がかかるステージ。")
            body += plotly_div_safe(fig_stage_bar, "career_stage_median", max(350, len(stage_labels_bar) * 50))
            body += "</div>"

    # C3-2: キャリア速度 密度散布図（credit数/年 vs ステージ進行速度）
    scores_career = get_feat_person_scores()
    if scores_career and isinstance(scores_career, list):
        speed_x = []
        speed_y = []
        speed_names = []
        for p in scores_career:
            active_yrs = _safe_nested(p, "career", "active_years", default=0)
            total_cred = float(p.get("total_credits", 0))
            highest_stage = _safe_nested(p, "career", "highest_stage", default=0)
            if active_yrs >= 2 and total_cred > 0:
                speed_x.append(total_cred / active_yrs)
                speed_y.append(highest_stage / active_yrs)
                speed_names.append(p.get("name", p.get("person_id", "")))
        if len(speed_x) > 10:
            fig_speed = density_scatter_2d(
                speed_x, speed_y,
                xlabel="年間クレジット数", ylabel="ステージ進行速度 (stage/yr)",
                title="キャリア速度 — 活動量 vs 昇進ペース",
                label_names=speed_names, label_top=10,
                height=520,
            )
            body += '<div class="card"><h2>キャリア速度分析（密度）</h2>'
            body += chart_guide(
                "密度等高線で年間クレジット数（活動量）とステージ進行速度の関係を表示。"
                "右上=多作かつ高速昇進のクラスタ。暖色域に大多数が集中し、"
                "ラベル付き点はステージ進行が特に速い人物。"
            )
            body += plotly_div_safe(fig_speed, "career_speed_density", 520)
            body += "</div>"

        # Add: Stage-based IV Violin (log-transformed for power-law distribution)
        if scores_career:
            import numpy as _np_iv
            stage_iv: dict[str, list[float]] = {}
            stage_names = ["0:新人", "1:若手", "2:中堅", "3:熟練", "4:ベテラン", "5:マスター", "6:レジェンド"]
            for p in scores_career:
                hs = int(_safe_nested(p, "career", "highest_stage", default=0))
                if 0 <= hs <= 6:
                    label = stage_names[hs]
                    stage_iv.setdefault(label, []).append(float(_np_iv.log1p(p.get("iv_score", 0))))
            if stage_iv:
                fig_siv = ridge_plot(
                    stage_iv,
                    title="キャリアステージ別 IV Score分布（log1p変換）",
                    xlabel="log1p(IV Score)",
                    height=450,
                )
                body += '<div class="card"><h2>ステージ別 IV Score</h2>'
                body += chart_guide(
                    "各キャリアステージのIV Score分布をKDEで重ね表示。"
                    "IVが分化し始めるステージ（中堅→熟練）が読み取れる。"
                    "レジェンド層の分布の狭さは高スコアの安定性を示す。"
                )
                body += plotly_div_safe(fig_siv, "stage_iv_ridge", 450)
                body += "</div>"

    # ----------------------------------------------------------------
    # Section: 監督分析（名目 + 規模別）
    # ----------------------------------------------------------------
    import sqlite3 as _sq3
    from src.database import get_connection as _get_conn
    from src.database import load_all_anime, load_all_credits, load_all_persons
    from src.analysis.career import (
        compute_director_scale_profiles,
        SCALE_KEYS_ORDERED,
        SCALE_KEY_LABELS,
    )
    import numpy as _np_dir

    try:
        _conn = _get_conn()
        _anime_list = load_all_anime(_conn)
        _credits_list = load_all_credits(_conn)
        _persons = load_all_persons(_conn)
        _conn.close()

        _anime_map = {a.id: a for a in _anime_list}
        _name_map = {p.id: (p.name_ja or p.name_en or p.id) for p in _persons}

        _dir_profiles = compute_director_scale_profiles(
            _credits_list, _anime_map, _name_map,
            director_roles={"director"},
            min_credits=3,
        )
    except Exception as _e:
        _dir_profiles = []

    if _dir_profiles:
        # --------------------------------------------------
        # Part A: 「監督」名目 — 総クレジット数ランキング
        # --------------------------------------------------
        body += '<div class="card">'
        body += "<h2>「監督」クレジット保有者 上位50名</h2>"
        body += chart_guide(
            "ロール「director」のクレジット数が多い人物の一覧。"
            "「名目上の監督」= 数字上クレジットが多い人物。規模や質は問わない純粋な量指標。"
            "クレジット数の多さは長期活動・多作品への参加を示すが、"
            "作品の規模（大・中・小）は右の規模別グラフを参照のこと。"
        )
        _top50 = _dir_profiles[:50]
        _dir_names_top = [p.name for p in _top50]
        _dir_totals_top = [p.total_director_credits for p in _top50]
        _dir_spans_top = [
            f"{p.first_year}–{p.latest_year}" if p.first_year else "不明"
            for p in _top50
        ]
        _dir_dominant_top = [SCALE_KEY_LABELS.get(p.dominant_type, p.dominant_type) for p in _top50]

        fig_dir_rank = go.Figure(go.Bar(
            y=_dir_names_top[::-1],
            x=_dir_totals_top[::-1],
            orientation="h",
            marker_color=[
                "#F72585" if d.startswith("TV大") else
                "#7209b7" if d.startswith("TV中") else
                "#4cc9f0" if d.startswith("TV小") else
                "#f77f00" if d.startswith("単発大") else
                "#fcbf49" if d.startswith("単発中") else
                "#2ec4b6"
                for d in _dir_dominant_top[::-1]
            ],
            customdata=list(zip(_dir_spans_top[::-1], _dir_dominant_top[::-1])),
            hovertemplate=(
                "<b>%{y}</b><br>監督クレジット: %{x}<br>"
                "活動期間: %{customdata[0]}<br>主要規模: %{customdata[1]}<extra></extra>"
            ),
            text=_dir_dominant_top[::-1],
            textposition="outside",
        ))
        fig_dir_rank.update_layout(
            title="監督クレジット数 上位50名（色=主要作品規模）",
            xaxis_title="監督クレジット数",
            height=max(600, len(_top50) * 18),
            margin=dict(l=160),
        )
        body += plotly_div_safe(fig_dir_rank, "dir_rank", max(600, len(_top50) * 18))
        body += "</div>"

        # Dominant type distribution
        from collections import Counter as _Counter
        _dom_counts = _Counter(
            SCALE_KEY_LABELS.get(p.dominant_type, p.dominant_type)
            for p in _dir_profiles
        )
        _dom_labels = list(_dom_counts.keys())
        _dom_vals = [_dom_counts[k] for k in _dom_labels]
        _scale_colors_map = {
            "TV大": "#F72585", "TV中": "#7209b7", "TV小": "#4cc9f0",
            "単発大": "#f77f00", "単発中": "#fcbf49", "単発小": "#2ec4b6",
        }
        fig_dom = go.Figure(go.Bar(
            x=_dom_labels,
            y=_dom_vals,
            marker_color=[_scale_colors_map.get(lb, "#888") for lb in _dom_labels],
            hovertemplate="%{x}: %{y}人<extra></extra>",
            text=_dom_vals,
            textposition="outside",
        ))
        fig_dom.update_layout(
            title="監督の主要作品規模 分布（n=全監督）",
            xaxis_title="主要作品規模",
            yaxis_title="監督人数",
            height=380,
        )
        body += '<div class="card">'
        body += "<h2>監督のドミナント規模 分布</h2>"
        body += chart_guide(
            "各監督の最多クレジット規模カテゴリ（ドミナント規模）の業界全体分布。"
            "「TV大」は長期・大規模TVシリーズを主戦場とする監督、「単発大」は劇場作品・大型OVA中心の監督。"
        )
        body += plotly_div_safe(fig_dom, "dir_dominant_dist", 380)
        body += "</div>"

        # --------------------------------------------------
        # Part B: 規模別監督 — スタック横棒 + ヒートマップ
        # --------------------------------------------------
        body += '<div class="card">'
        body += "<h2>規模別監督プロフィール（上位60名）</h2>"
        body += chart_guide(
            "各監督の監督クレジットを作品タイプ×規模に分解したスタック棒グラフ。"
            "1本の棒が1人の監督で、各セグメントが規模カテゴリの割合を示す。"
            "「TV大だけに集中している監督」と「TV小から単発まで幅広い監督」の違いが一目で分かる。"
        )
        _top60 = _dir_profiles[:60]
        _scale_colors = {
            "tv_large": "#F72585",
            "tv_medium": "#7209b7",
            "tv_small": "#4cc9f0",
            "tanpatsu_large": "#f77f00",
            "tanpatsu_medium": "#fcbf49",
            "tanpatsu_small": "#2ec4b6",
        }
        fig_stack = go.Figure()
        for sk in SCALE_KEYS_ORDERED:
            _vals = [p.scale_fractions.get(sk, 0.0) * 100 for p in _top60]
            fig_stack.add_trace(go.Bar(
                name=SCALE_KEY_LABELS[sk],
                y=[p.name for p in _top60],
                x=_vals,
                orientation="h",
                marker_color=_scale_colors[sk],
                hovertemplate=(
                    f"<b>%{{y}}</b> — {SCALE_KEY_LABELS[sk]}: %{{x:.1f}}%<extra></extra>"
                ),
            ))
        fig_stack.update_layout(
            barmode="stack",
            title="監督クレジットの作品規模内訳（%）上位60名",
            xaxis_title="割合 (%)",
            xaxis=dict(range=[0, 100]),
            height=max(700, len(_top60) * 14),
            legend=dict(orientation="h", y=1.02),
            margin=dict(l=160),
        )
        body += plotly_div_safe(fig_stack, "dir_scale_stack", max(700, len(_top60) * 14))
        body += "</div>"

        # Heatmap: directors × scale (percentage)
        body += '<div class="card">'
        body += "<h2>規模別監督ヒートマップ（上位40名）</h2>"
        body += chart_guide(
            "監督（行）× 作品規模（列）の割合ヒートマップ。"
            "明るいセルほどその監督のクレジットにその規模が多い。"
            "行を横に読むと各監督の「得意フィールド」が分かる。"
        )
        _top40 = _dir_profiles[:40]
        _hm_z = [
            [p.scale_fractions.get(sk, 0.0) * 100 for sk in SCALE_KEYS_ORDERED]
            for p in _top40
        ]
        fig_hm = go.Figure(go.Heatmap(
            z=_hm_z,
            x=[SCALE_KEY_LABELS[sk] for sk in SCALE_KEYS_ORDERED],
            y=[p.name for p in _top40],
            colorscale="Plasma",
            text=[[f"{v:.0f}%" for v in row] for row in _hm_z],
            texttemplate="%{text}",
            hovertemplate="<b>%{y}</b><br>%{x}: %{z:.1f}%<extra></extra>",
            zmin=0, zmax=100,
        ))
        fig_hm.update_layout(
            title="監督 × 作品規模 ヒートマップ（%）",
            height=max(600, len(_top40) * 18),
            margin=dict(l=160),
        )
        body += plotly_div_safe(fig_hm, "dir_scale_heatmap", max(600, len(_top40) * 18))
        body += "</div>"

        # Career span distribution by dominant type
        _span_by_dom: dict[str, list[int]] = {}
        for p in _dir_profiles:
            if p.career_span:
                lb = SCALE_KEY_LABELS.get(p.dominant_type, p.dominant_type)
                _span_by_dom.setdefault(lb, []).append(p.career_span)

        if len(_span_by_dom) >= 2:
            fig_span = go.Figure()
            for lb, spans in sorted(_span_by_dom.items()):
                fig_span.add_trace(go.Violin(
                    x=[lb] * len(spans),
                    y=spans,
                    name=lb,
                    box_visible=True,
                    meanline_visible=True,
                    fillcolor=_scale_colors_map.get(lb, "#888"),
                    line_color="#fff",
                    opacity=0.8,
                ))
            fig_span.update_layout(
                title="主要規模別 監督キャリアスパン分布",
                xaxis_title="主要作品規模",
                yaxis_title="キャリアスパン（年）",
                violinmode="group",
                height=420,
            )
            body += '<div class="card">'
            body += "<h2>規模別 監督キャリアスパン</h2>"
            body += chart_guide(
                "各作品規模を主戦場とする監督のキャリア年数分布。"
                "「TV大」監督は長期キャリアが多い（長期シリーズに継続参加）傾向が見られるか確認できる。"
            )
            body += plotly_div_safe(fig_span, "dir_span_violin", 420)
            body += "</div>"

    # --------------------------------------------------
    # Part C: キャリア軌跡 + 規模間モビリティ
    # --------------------------------------------------
    if _dir_profiles:
        from src.analysis.career import compute_director_trajectories, SCALE_KEY_LABELS, SCALE_KEYS_ORDERED

        _traj = compute_director_trajectories(
            _credits_list, _anime_map,
            director_roles={"director"},
            min_director_credits=3,
        )

        # C-1: 規模別「初監督デビューまでの経験年数」Ridge Plot
        _traj_groups = {
            SCALE_KEY_LABELS[sk]: _traj.years_to_first_dir_by_scale.get(sk, [])
            for sk in SCALE_KEYS_ORDERED
            if _traj.years_to_first_dir_by_scale.get(sk)
        }
        if _traj_groups:
            body += '<div class="card">'
            body += "<h2>各規模の初監督デビューまでの経験年数</h2>"
            body += chart_guide(
                "最初の業界クレジットから、各規模カテゴリで初めて監督クレジットを得るまでの年数分布（KDE）。"
                "「TV大」のp25が低い（=早期デビューが多い）のは、長期シリーズに話数演出として参加しやすいため。"
                "「単発大」のロングテール（ゆっくり達成）は劇場・大型OVAの関門の高さを反映する。"
                "白線=中央値。"
            )
            fig_traj = ridge_plot(
                _traj_groups,
                title="規模別 初監督デビューまでの経験年数 (Ridge Plot)",
                xlabel="経験年数（初クレジットからの年数）",
                height=max(450, len(_traj_groups) * 75),
            )
            body += plotly_div_safe(fig_traj, "dir_years_to_debut", max(450, len(_traj_groups) * 75))
            body += "</div>"

        # C-2: 規模間モビリティ — 推移確率ヒートマップ
        _prob_z = [
            [_traj.transition_probs.get((sk_f, sk_t), 0.0) * 100
             for sk_t in SCALE_KEYS_ORDERED]
            for sk_f in SCALE_KEYS_ORDERED
        ]
        _row_labels = [SCALE_KEY_LABELS[sk] for sk in SCALE_KEYS_ORDERED]
        _row_ns = [
            sum(_traj.transition_counts.get((sk_f, sk_t), 0) for sk_t in SCALE_KEYS_ORDERED)
            for sk_f in SCALE_KEYS_ORDERED
        ]
        _ylabels_with_n = [
            f"{SCALE_KEY_LABELS[sk]}  (n={_row_ns[i]})"
            for i, sk in enumerate(SCALE_KEYS_ORDERED)
        ]

        fig_mob = go.Figure(go.Heatmap(
            z=_prob_z,
            x=_row_labels,
            y=_ylabels_with_n,
            colorscale="Plasma",
            text=[[f"{v:.1f}%" for v in row] for row in _prob_z],
            texttemplate="%{text}",
            hovertemplate="<b>%{y} → %{x}</b><br>確率: %{z:.1f}%<extra></extra>",
            zmin=0, zmax=60,
        ))
        fig_mob.update_layout(
            title="規模間モビリティ行列 — 翌年の監督作品規模（行 → 列）",
            xaxis_title="翌年の規模",
            yaxis_title="今年の規模",
            height=420,
        )
        body += '<div class="card">'
        body += "<h2>規模間モビリティ行列</h2>"
        body += chart_guide(
            "ある規模カテゴリで監督した翌年（3年以内）に、どの規模カテゴリで監督するかの確率行列。"
            "対角線（同規模継続）が最大 = 一度入った規模からは動きにくい。"
            "TV中→TV大 ≈16%、TV小→TV中 ≈14% の上昇移動が存在する。"
            "単発大→TV大 ≈27% は「劇場監督がTVに戻る」パターンを示す。"
            "各行のn=その規模から翌年クレジットが確認された人-年数。"
        )
        body += plotly_div_safe(fig_mob, "dir_mobility_heatmap", 420)
        body += "</div>"

        # C-3: Sankey — 規模間フロー（有向グラフ）
        _sankey_links = []
        for sk_f in SCALE_KEYS_ORDERED:
            for sk_t in SCALE_KEYS_ORDERED:
                cnt = _traj.transition_counts.get((sk_f, sk_t), 0)
                if cnt >= 10:
                    _sankey_links.append((sk_f, sk_t, cnt))

        if _sankey_links:
            # Duplicate nodes: "from" side と "to" side を別ノードにして左→右の流れを作る
            _from_nodes = [f"{SCALE_KEY_LABELS[sk]}（前年）" for sk in SCALE_KEYS_ORDERED]
            _to_nodes   = [f"{SCALE_KEY_LABELS[sk]}（翌年）" for sk in SCALE_KEYS_ORDERED]
            _all_nodes  = _from_nodes + _to_nodes
            _node_idx   = {n: i for i, n in enumerate(_all_nodes)}
            _sk_colors  = ["#F72585","#7209b7","#4cc9f0","#f77f00","#fcbf49","#2ec4b6"]
            _node_colors = _sk_colors + _sk_colors

            _src = [_node_idx[f"{SCALE_KEY_LABELS[sk_f]}（前年）"] for sk_f, _, _ in _sankey_links]
            _tgt = [_node_idx[f"{SCALE_KEY_LABELS[sk_t]}（翌年）"] for _, sk_t, _ in _sankey_links]
            _vals= [cnt for _, _, cnt in _sankey_links]

            fig_sankey = go.Figure(go.Sankey(
                node=dict(
                    pad=15, thickness=20,
                    label=_all_nodes,
                    color=_node_colors,
                ),
                link=dict(
                    source=_src, target=_tgt, value=_vals,
                    color=[
                        _sk_colors[SCALE_KEYS_ORDERED.index(sk_f)].replace(
                            "#", "rgba(").rstrip(")") + ",0.35)"
                        if False else "rgba(180,180,200,0.3)"
                        for sk_f, _, _ in _sankey_links
                    ],
                ),
            ))
            fig_sankey.update_layout(
                title="監督の規模間フロー（前年→翌年、10件以上の遷移のみ表示）",
                height=480,
            )
            body += '<div class="card">'
            body += "<h2>規模間フロー（Sankey）</h2>"
            body += chart_guide(
                "前年の監督規模から翌年の監督規模への人数フロー。"
                "帯の太さ = 遷移した人-年数。左=前年の規模、右=翌年の規模。"
                "同規模への自己ループが最大で、TV大の帯が他規模と接続している。"
            )
            body += plotly_div_safe(fig_sankey, "dir_scale_sankey", 480)
            body += "</div>"

        # C-4: 散布図 — 経験年数 vs 最初に達した最高規模
        # 規模の順位: tv_large=5, tanpatsu_large=4, tv_medium=3, tanpatsu_medium=2, tv_small=1, tanpatsu_small=0
        _SCALE_RANK = {
            "tv_large": 5, "tanpatsu_large": 4,
            "tv_medium": 3, "tanpatsu_medium": 2,
            "tv_small": 1, "tanpatsu_small": 0,
        }
        _scatter_x = []  # 経験年数
        _scatter_y = []  # 最高規模ランク
        _scatter_label = []
        for p in _dir_profiles:
            if not p.first_year:
                continue
            # first_year は監督クレジットの初年。全クレジット初年はDBから取得困難なため
            # 近似: dominant scaleの初デビュー年数を使用
            if not p.scale_counts:
                continue
            best_scale = max(p.scale_counts, key=lambda k: _SCALE_RANK.get(k, -1))
            best_rank = _SCALE_RANK.get(best_scale, -1)
            exp_years = (p.latest_year or p.first_year) - p.first_year
            if exp_years >= 0 and best_rank >= 0:
                _scatter_x.append(exp_years)
                _scatter_y.append(best_rank + _np_dir.random.uniform(-0.15, 0.15))
                _scatter_label.append(p.name)

        if len(_scatter_x) > 50:
            fig_exp = density_scatter_2d(
                _scatter_x, _scatter_y,
                xlabel="監督としての活動スパン（年）",
                ylabel="達成した最高規模ランク（0=単発小, 5=TV大）",
                title="監督経験スパン vs 達成規模",
                label_names=_scatter_label, label_top=15,
                height=500,
            )
            body += '<div class="card">'
            body += "<h2>監督経験スパン × 達成規模</h2>"
            body += chart_guide(
                "横軸=監督クレジットのキャリアスパン（年）、縦軸=達成した最高規模ランク。"
                "TV大（5）を達成している監督はキャリアスパンが広い傾向がある一方、"
                "短いキャリアでもTV大に到達した監督（右上）は例外的な早期昇進を示す。"
                "密度等高線で大多数のパターンを把握できる。"
            )
            body += plotly_div_safe(fig_exp, "dir_exp_vs_scale", 500)
            body += "</div>"

    # Data-driven key findings
    total_analyzed_c = transitions.get("total_persons_analyzed", 0) if transitions else 0
    trans_count = len(transitions.get("transitions", [])) if transitions else 0
    paths_count = len(transitions.get("career_paths", [])) if transitions else 0
    body += key_findings([
        f"分析対象 {fmt_num(total_analyzed_c)} 人のキャリアから "
        f"{fmt_num(trans_count)} 種類の遷移パターンと {fmt_num(paths_count)} 本のキャリアパスを検出",
        "各ステージ到達までの平均年数は個人差が大きく、"
        "中央値との乖離が遅咲き人材の存在を示す",
        "最も一般的なキャリアパスは少数のルートに集中しており、"
        "業界標準のキャリア進行が存在する",
    ])

    body += significance_section("キャリアパスの客観的な可視化", [
        "アニメ業界のキャリアパスはこれまで「先輩の背中を見て学ぶ」暗黙知に依存していました。"
        "本分析は100年以上のクレジットデータからキャリア進行の実態を数値化し、"
        "育成計画・昇進基準・報酬設計の根拠となる客観的なデータを初めて提供します。",
        "「ベテランになるまで平均何年かかるか」「どのルートが一般的か」が明確になることで、"
        "キャリア設計指導が感覚論を脱却し、また人材が特定のステージに滞留している"
        "ボトルネックを可視化することで、スタジオの育成投資の優先順位が決まります。",
    ])
    body += utilization_guide([
        {"role": "人事・研修担当", "how": "Time to Stageチャートの各ステージ到達の平均・中央値年数を社内の昇進基準に照合し、業界水準と乖離がある場合は制度見直しの根拠として使う"},
        {"role": "キャリアカウンセラー", "how": "Transition Matrixで相談者の現在のステージ行を横に読み、遷移頻度が高い（明るいセルの）次のステージを具体的なキャリア目標として提示する"},
        {"role": "新人アニメーター", "how": "Career Pathsテーブルで最も一般的なルートと自分の現在地を照らし合わせ、次の役職への遷移に何年かかるかの目安を把握して計画を立てる"},
        {"role": "スタジオ経営者", "how": "自社の人材が特定のステージに平均より長く滞留している場合、そのステージへの集中育成投資の根拠として遷移データを提示して予算承認を得る"},
    ])
    body += future_possibilities([
        "キャリアステージ別の市場報酬データとの統合による「ステージ到達時の適正報酬レンジ」の算出",
        "ステージ滞留リスクアラート（業界平均より長くとどまっている人物への昇進機会の提案）",
        "海外アニメ業界のキャリアパスとの比較（日本特有のキャリア進行パターンの国際的位置づけ）",
        "役職間遷移確率を使った「次の役職」予測モデル（各人物の現在地から最も到達しやすい次のポジションを提示）",
    ])

    html = wrap_html(
        "キャリア遷移分析",
        f"キャリアステージ遷移分析 — {fmt_num(transitions.get('total_persons_analyzed', 0) if transitions else 0)}人を分析",
        body,
        intro_html=report_intro(
            "キャリア遷移分析",
            "アニメ業界のプロフェッショナルはどのようにキャリアステージを進むのか？"
            "本レポートでは役職間の遷移パターンを可視化し、各キャリアステージ到達までの"
            "平均期間を示し、最も一般的なキャリアパスをサンキーフローで表現します。",
            "キャリアアドバイザー、アニメーター志望者、人事部門",
        ),
        glossary_terms={
            **COMMON_GLOSSARY_TERMS,
            "キャリアステージ (Career Stage)": (
                "クレジット履歴の期間と役職の進行に基づく人物の段階分類"
                "（新人・中堅・ベテラン・マスターなど）。"
            ),
            "遷移行列 (Transition Matrix)": (
                "キャリアステージ間の遷移頻度を示すグリッド。"
                "各セル(行,列)=行のステージから列のステージへ移った人数。"
            ),
            "サンキーダイアグラム (Sankey Diagram)": (
                "帯の幅が役職間の遷移量を表すフロー可視化。"
                "主要なキャリアパスを一目で把握できます。"
            ),
        },
    )
    out = REPORTS_DIR / "career_transitions.html"
    out.write_text(html, encoding="utf-8")
    print(f"    -> {out}")


# ============================================================
# Report 5: Temporal BiRank & Foresight
# ============================================================

def generate_temporal_report():
    """時系列BiRank・先見レポート."""
    print("  Generating Temporal BiRank & Foresight Report...")
    tp = get_feat_birank_annual()
    if not tp:
        return

    timelines = tp.get("authority_timelines", {})
    foresight = tp.get("foresight_scores", {})
    promotions = tp.get("promotion_credits", {})
    years_computed = tp.get("years_computed", [])

    body = ""

    # Summary stats
    body += '<div class="card">'
    body += "<h2>Temporal PageRank Summary</h2>"
    body += '<div class="stats-grid">'
    for label, val in [
        ("Total Persons", fmt_num(tp.get("total_persons", 0))),
        ("Years Computed", fmt_num(len(years_computed))),
        ("Foresight Persons", fmt_num(len(foresight))),
        ("Promotion Persons", fmt_num(len(promotions))),
        ("Computation Time", f"{tp.get('computation_time_seconds', 0):.1f}s"),
        ("Year Range", f"{min(years_computed)}-{max(years_computed)}" if years_computed else "N/A"),
    ]:
        body += f'<div class="stat-card"><div class="value">{val}</div><div class="label">{label}</div></div>'
    body += "</div></div>"

    # Top persons by peak authority — sample 20 with highest peak
    persons_by_peak = []
    for pid, data in timelines.items():
        persons_by_peak.append((pid, data.get("peak_authority", 0), data.get("peak_year", 0), data))
    persons_by_peak.sort(key=lambda x: x[1], reverse=True)

    # BiRank timeline for top 10
    if persons_by_peak:
        fig = go.Figure()
        for pid, peak_auth, peak_yr, data in persons_by_peak[:10]:
            snapshots = data.get("snapshots", [])
            if snapshots:
                fig.add_trace(go.Scatter(
                    x=[s["year"] for s in snapshots],
                    y=[s["birank"] for s in snapshots],
                    mode="lines+markers",
                    name=f"{data.get('name', pid)[:20]} (peak={peak_auth:.2f})",
                    hovertemplate="%{x}: %{y:.4f}<extra></extra>",
                    line=dict(width=2),
                    marker=dict(size=5),
                ))
        fig.update_layout(title="BiRank Evolution — Top 10 Persons", xaxis_title="Year", yaxis_title="BiRank Score")

        body += '<div class="card">'
        body += "<h2>BiRank Evolution (Top 10)</h2>"
        body += chart_guide(
            "各線は1人のBiRankの時系列推移。上昇線はネットワーク影響力の"
            "増大、ピーク後の下降はキャリアフェーズの転換を示唆します。"
            "ホバーで年次の正確な値を確認できます。"
        )
        body += plotly_div_safe(fig, "authority_timeline", 550)
        body += "</div>"

    # Dual-axis: BiRank + Cumulative Credits for top 5
    if persons_by_peak[:5]:
        fig_da = make_subplots(specs=[[{"secondary_y": True}]])
        da_colors = ["#f093fb", "#a0d2db", "#f5576c", "#fda085", "#667eea"]
        for idx, (pid, peak_auth, peak_yr, data) in enumerate(persons_by_peak[:5]):
            snapshots = data.get("snapshots", [])
            if not snapshots:
                continue
            p_name = data.get("name", pid)[:20]
            color = da_colors[idx % len(da_colors)]
            years_s = [s["year"] for s in snapshots]
            birank_vals = [s["birank"] for s in snapshots]
            cum_credits = [s.get("n_credits_cumulative", 0) for s in snapshots]

            fig_da.add_trace(
                go.Scatter(
                    x=years_s, y=birank_vals,
                    mode="lines+markers",
                    name=f"{p_name} BiRank",
                    line=dict(color=color, width=2),
                    marker=dict(size=4),
                    hovertemplate="%{x}: BiRank %{y:.4f}<extra></extra>",
                ),
                secondary_y=False,
            )
            if any(c > 0 for c in cum_credits):
                fig_da.add_trace(
                    go.Scatter(
                        x=years_s, y=cum_credits,
                        mode="lines",
                        name=f"{p_name} Credits",
                        line=dict(color=color, width=1, dash="dot"),
                        opacity=0.5,
                        hovertemplate="%{x}: %{y}クレジット<extra></extra>",
                    ),
                    secondary_y=True,
                )
        fig_da.update_layout(title="BiRank推移 + 累積クレジット数（Top 5 Dual-axis）")
        fig_da.update_yaxes(title_text="BiRank Score", secondary_y=False)
        fig_da.update_yaxes(title_text="累積クレジット数", secondary_y=True)

        body += '<div class="card">'
        body += "<h2>BiRank推移 + 累積クレジット数（Top 5）</h2>"
        body += chart_guide(
            "左Y軸（実線）: BiRankの推移、右Y軸（点線）: 累積クレジット数。"
            "クレジット数が増加してもBiRankが上がらない場合は「量は増えたが質的影響力は停滞」を示唆。"
            "逆にクレジット数が少なくてもBiRank上昇は「少数の高影響力作品に参加」を意味します。"
        )
        body += plotly_div_safe(fig_da, "authority_dual_axis", 550)
        body += "</div>"

    # Top persons table
    n_censored = sum(1 for _, _, _, d in persons_by_peak if d.get("is_censored"))
    body += '<div class="card">'
    body += "<h2>Top 30 by Peak BiRank</h2>"
    if n_censored:
        body += (
            f'<div class="insight-box" style="border-left-color:#f5a623">'
            f"<strong>右打ち切り注意:</strong> {n_censored} 人が 2022年以降も活動中のため、"
            "観測済みピークは真のピークの下限値です。現役者のピーク順位は過小評価される傾向があります。"
            "</div>"
        )
    body += "<table><thead><tr>"
    body += "<th>#</th><th>Person</th><th>Peak BiRank</th><th>Peak Year</th><th>Career Start</th><th>Trajectory</th><th>Status</th>"
    body += "</tr></thead><tbody>"
    for i, (pid, peak, peak_yr, data) in enumerate(persons_by_peak[:30], 1):
        traj = data.get("trajectory", "unknown")
        badge = "badge-high" if traj == "rising" else "badge-mid" if traj == "stable" else "badge-low"
        t_name = data.get("name") or pid
        censored = data.get("is_censored", False)
        status_cell = '<span class="badge badge-mid">現役(打ち切り)</span>' if censored else '<span class="badge badge-low">確定</span>'
        body += f"<tr><td>{i}</td><td>{t_name}</td><td>{peak:.4f}</td><td>{peak_yr}</td>"
        body += f"<td>{data.get('career_start_year', '')}</td>"
        body += f'<td><span class="badge {badge}">{traj}</span></td>'
        body += f"<td>{status_cell}</td></tr>"
    body += "</tbody></table></div>"

    # Holdout validation section (insert before foresight scores)
    holdout = tp.get("holdout_validation", {})
    if holdout and "error" not in holdout:
        body += '<div class="card">'
        body += "<h2>先見スコア — ホールドアウト予測検証</h2>"
        body += (
            '<div class="insight-box" style="border-left-color:#f5a623">'
            "<strong>方法論上の注意:</strong> 先見スコアは定義上「後知恵」の指標です。"
            "スコアは <em>全データ</em> を用いて「誰が後に高ランクになった人と早期に共演していたか」を遡って計算します。"
            "以下のホールドアウト検証では、2018年以前のデータのみでスコアを計算し、"
            "2019年以降のブレイク人材をどれだけ説明できるかを2つの素朴ベースラインと比較します。"
            "</div>"
        )
        h_year = holdout.get("holdout_year", 2018)
        n_unk = holdout.get("n_unknowns", 0)
        n_br = holdout.get("n_breakouts", 0)
        br_rate = holdout.get("breakout_rate", 0)
        roc = holdout.get("roc_auc", {})
        pak = holdout.get("precision_at_k", {})

        # ROC-AUC bar chart
        roc_labels = ["先見スコア", "活動量ベースライン", "共演者平均BiRank"]
        roc_vals = [roc.get("foresight", 0.5), roc.get("baseline_activity", 0.5), roc.get("baseline_partner_birank", 0.5)]
        roc_colors = ["#f093fb", "#a0d2db", "#fda085"]
        fig_roc = go.Figure(go.Bar(
            x=roc_labels, y=roc_vals,
            marker_color=roc_colors,
            text=[f"{v:.3f}" for v in roc_vals],
            textposition="outside",
        ))
        fig_roc.add_hline(y=0.5, line_dash="dash", line_color="#888", annotation_text="ランダム (0.50)")
        fig_roc.update_layout(
            title=f"ROC-AUC: {h_year}以前データ → {h_year+1}以降ブレイク予測",
            yaxis_title="ROC-AUC", yaxis_range=[0.4, 1.0],
            xaxis_title="",
        )
        body += chart_guide(
            f"訓練データ: {h_year}年以前のクレジット。"
            f"テスト: {n_unk:,}人の低BiRank者のうち{n_br:,}人({br_rate:.1%})が{h_year+1}以降にブレイク。"
            "0.5=ランダム予測と同等。0.6以上でベースラインを超える予測力があると解釈できます。"
        )
        body += plotly_div_safe(fig_roc, "holdout_roc", 400)

        # Precision@k table
        if pak:
            body += "<h3>Precision@k 比較</h3>"
            body += "<table><thead><tr><th>k</th><th>先見スコア</th><th>活動量</th><th>共演者平均BiRank</th><th>ランダム</th></tr></thead><tbody>"
            for k_str, row in sorted(pak.items(), key=lambda x: int(x[0])):
                fs_p = row.get("foresight", 0)
                bl_a = row.get("baseline_activity", 0)
                bl_p = row.get("baseline_partner_birank", 0)
                rand = row.get("random_baseline", 0)
                best = max(fs_p, bl_a, bl_p)
                def _fmt(v: float, is_best: bool) -> str:
                    s = f"{v:.3f}"
                    return f"<strong>{s}</strong>" if is_best and v == best else s
                body += (
                    f"<tr><td>@{k_str}</td>"
                    f"<td>{_fmt(fs_p, True)}</td>"
                    f"<td>{_fmt(bl_a, True)}</td>"
                    f"<td>{_fmt(bl_p, True)}</td>"
                    f"<td>{rand:.3f}</td></tr>"
                )
            body += "</tbody></table>"
        body += (
            '<details><summary><strong>[方法論ノート — Layer 3]</strong></summary>'
            "<p>ブレイク定義: ホールドアウト時点のBiRank &lt; 40パーセンタイル かつ その後 &gt; 65パーセンタイル到達。"
            "先見信号: sum(1/(y_birank+1)) for each pre-holdout co-appearance with unknown Y。"
            "ROC-AUCはWilcoxon-Mann-Whitney U統計量。"
            "近年の発見者は「発見→検証ラグ」により系統的に過小評価される（右打ち切り問題と同構造）。</p>"
            "</details>"
        )
        body += "</div>"
    elif holdout.get("error"):
        body += (
            f'<div class="card"><div class="insight-box" style="border-left-color:#e74c3c">'
            f"<strong>ホールドアウト検証スキップ:</strong> {holdout.get('error')} "
            f"(n_unknowns={holdout.get('n_unknowns', 'N/A')}, n_breakouts={holdout.get('n_breakouts', 'N/A')})"
            "</div></div>"
        )

    # Foresight scores
    if foresight:
        foresight_list = sorted(foresight.values(), key=lambda x: x.get("foresight_normalized", 0), reverse=True)

        body += '<div class="card">'
        body += "<h2>先見的共演パターン (Retrospective Co-appearance Score)</h2>"
        body += (
            '<div class="insight-box">'
            f"<strong>事後的パターン検出:</strong> {len(foresight_list)} 人が、"
            "後に高BiRankを獲得した人物と、その人物がまだ低BiRankだった時期に共演していた構造的パターンを持ちます。"
            "このスコアは「目利き能力の証明」ではなく「共演パターンの記述」です。"
            "スコアが高いほど、将来のスターと早期に同じ現場にいた回数と規模が大きい。"
            "</div>"
        )

        # Foresight distribution
        fig = go.Figure(go.Histogram(
            x=[f["foresight_normalized"] for f in foresight_list],
            nbinsx=30, marker_color="#f093fb",
            hovertemplate="Score: %{x:.1f}<br>Count: %{y}<extra></extra>",
        ))
        fig.update_layout(title="共演パターンスコア分布", xaxis_title="Score (Normalized)", yaxis_title="Count", yaxis_type="log")
        body += chart_guide(
            "スコアは「後に高ランクになった人と、彼らがまだ無名だった時期に共演した頻度×強度」の事後計算値。"
            "分布は右に偏っており、大多数が低スコア、少数が構造的に多くのブレイク人材と同じ現場にいた。"
        )
        body += plotly_div_safe(fig, "foresight_dist", 400)

        # Scatter: Foresight Score vs Discoveries
        if len(foresight_list) >= 5:
            fig_fs = go.Figure(go.Scatter(
                x=[f.get("n_discoveries", 0) for f in foresight_list],
                y=[f.get("foresight_normalized", 0) for f in foresight_list],
                mode="markers",
                marker=dict(
                    size=8,
                    color=[f.get("confidence_upper", 0) - f.get("confidence_lower", 0)
                           for f in foresight_list],
                    colorscale="Viridis", showscale=True,
                    colorbar=dict(title="Bootstrap CI幅"),
                    opacity=0.7,
                ),
                text=[f.get("name") or f["person_id"] for f in foresight_list],
                hovertemplate="%{text}<br>共演人数: %{x}<br>Score: %{y:.1f}<br>"
                              "CI幅: %{marker.color:.1f}<extra></extra>",
            ))
            fig_fs.update_layout(
                title="共演パターンスコア vs 対象人数",
                xaxis_title="後にブレイクした共演者数",
                yaxis_title="Score (Normalized)",
                xaxis_type="log",
            )
            body += "<h3>スコア vs 対象人数</h3>"
            body += chart_guide(
                "X=後にブレイクした共演者の延べ人数、Y=スコア（正規化）、色=Bootstrap信頼区間幅（狭いほど安定）。"
                "右上ほど「多くのブレイク人材と早期に共演していた」。"
                "ただし活動量が多いほどスコアが上がる傾向があり（上記ホールドアウト検証参照）、"
                "単純な活動量効果との分離が今後の課題。"
            )
            body += plotly_div_safe(fig_fs, "foresight_scatter", 500)

        # Top foresight table
        body += "<h3>Top 30 — 共演パターンスコア上位</h3>"
        body += "<table><thead><tr>"
        body += "<th>#</th><th>氏名</th><th>Score</th><th>Raw</th><th>共演人数</th><th>Bootstrap 95% CI</th>"
        body += "</tr></thead><tbody>"
        for i, f in enumerate(foresight_list[:30], 1):
            norm = f.get("foresight_normalized", 0)
            badge = "badge-high" if norm >= 70 else "badge-mid" if norm >= 30 else "badge-low"
            ci_lo = f.get("confidence_lower", 0)
            ci_hi = f.get("confidence_upper", 0)
            conf = f"[{ci_lo:.1f}, {ci_hi:.1f}]"
            f_name = f.get("name") or f["person_id"]
            body += f"<tr><td>{i}</td><td>{f_name}</td>"
            body += f'<td><span class="badge {badge}">{norm:.1f}</span></td>'
            body += f"<td>{f.get('foresight_raw', 0):.4f}</td>"
            body += f"<td>{f.get('n_discoveries', 0)}</td><td>{conf}</td></tr>"
        body += "</tbody></table>"
        body += (
            '<details><summary><strong>[方法論ノート — Layer 3]</strong></summary>'
            "<p>Algorithm: 年T において birank &lt; 25th pct の人物Y と共演した established 者X に対し、"
            "Yが T+10年以内に +5pt 以上 birank 成長した場合、X に growth×1/(y_birank+1) を加算。"
            "Bootstrap CI: 200 iterations (events をリサンプル)。"
            "既知の限界: (1)共演=指導ではない (2)活動量と強く相関 (3)右打ち切りにより近年の発見者は過小評価。</p>"
            "</details>"
        )
        body += "</div>"

    # Promotion analysis
    if promotions:
        # Rank by shrunk_success_rate (Beta-Binomial posterior mean) — preferred over raw rate
        promo_list = sorted(
            promotions.values(),
            key=lambda x: x.get("shrunk_success_rate", x.get("promotion_success_rate", 0)),
            reverse=True,
        )

        body += '<div class="card">'
        body += "<h2>昇進クレジット分析</h2>"
        body += (
            f'<div class="insight-box"><strong>{len(promo_list)}</strong> 人がキャリアステージ昇進イベントの帰属先として記録されています。<br>'
            "<strong>定義上の注意:</strong> ここでの「昇進」は「同じ現場で上位役職者が最上位」として帰属されたもので、"
            "直接の指導関係とは区別が必要です。30人いる現場で1人が後に昇進すれば、残り29人全員にもカウントが付きます。<br>"
            "ランキングは <strong>Beta-Binomial縮約後成功率</strong>（試行数が少ない人物の極端な値を母集団平均方向に修正）。"
            "vs Baseline列は実際の成功率÷ステージコホート基準値（例: 2.3x＝同ステージ集団の2.3倍の成功率）。"
            "</div>"
        )

        # Dual histogram: raw rate vs shrunk rate
        if any(p.get("shrunk_success_rate", 0) > 0 for p in promo_list):
            raw_rates = [p.get("promotion_success_rate", 0) * 100 for p in promo_list]
            shrunk_rates = [p.get("shrunk_success_rate", p.get("promotion_success_rate", 0)) * 100 for p in promo_list]
            fig_promo = go.Figure()
            fig_promo.add_trace(go.Histogram(
                x=raw_rates, name="素の成功率", nbinsx=20, marker_color="#a0d2db", opacity=0.7,
                hovertemplate="Rate: %{x:.0f}%<br>Count: %{y}<extra>素の成功率</extra>",
            ))
            fig_promo.add_trace(go.Histogram(
                x=shrunk_rates, name="縮約後成功率", nbinsx=20, marker_color="#f093fb", opacity=0.7,
                hovertemplate="Rate: %{x:.0f}%<br>Count: %{y}<extra>縮約後</extra>",
            ))
            fig_promo.update_layout(
                title="昇進成功率分布: 素の値 vs Beta-Binomial縮約後",
                xaxis_title="Success Rate (%)", yaxis_title="Count",
                barmode="overlay",
            )
            body += chart_guide(
                "素の成功率（水色）は試行数が少ない人物で0%か100%に張り付く。"
                "Beta-Binomial縮約後（紫）は母集団の事前分布で補正し、試行数が少ないほど平均値に引き寄せられる。"
                "縮約後の値がランキングの基準。"
            )
            body += plotly_div_safe(fig_promo, "promo_dist", 420)
        else:
            fig = go.Figure(go.Histogram(
                x=[p.get("promotion_success_rate", 0) * 100 for p in promo_list],
                nbinsx=20, marker_color="#a0d2db",
                hovertemplate="Rate: %{x:.0f}%<br>Count: %{y}<extra></extra>",
            ))
            fig.update_layout(title="昇進成功率分布", xaxis_title="Success Rate (%)", yaxis_title="Count")
            body += plotly_div_safe(fig, "promo_dist", 400)

        # Top promoters table — ranked by shrunk rate
        body += "<h3>Top 20 — Beta-Binomial縮約後成功率ランキング</h3>"
        body += "<table><thead><tr>"
        body += "<th>#</th><th>氏名</th><th>昇進数</th><th>成功数</th><th>素の成功率</th><th>縮約後成功率</th><th>vs Baseline</th>"
        body += "</tr></thead><tbody>"
        for i, p in enumerate(promo_list[:20], 1):
            raw_rate = p.get("promotion_success_rate", 0) * 100
            shrunk = p.get("shrunk_success_rate", p.get("promotion_success_rate", 0)) * 100
            vs_bl = p.get("vs_cohort_baseline", 0)
            badge = "badge-high" if shrunk >= 50 else "badge-mid" if shrunk >= 25 else "badge-low"
            bl_badge = "badge-high" if vs_bl >= 2.0 else "badge-mid" if vs_bl >= 1.0 else "badge-low"
            p_name = p.get("name") or p["person_id"]
            body += f"<tr><td>{i}</td><td>{p_name}</td>"
            body += f"<td>{p.get('promotion_count', 0)}</td><td>{p.get('successful_promotions', 0)}</td>"
            body += f"<td>{raw_rate:.0f}%</td>"
            body += f'<td><span class="badge {badge}">{shrunk:.0f}%</span></td>'
            body += f'<td><span class="badge {bl_badge}">{vs_bl:.2f}x</span></td></tr>'
        body += "</tbody></table>"
        body += (
            '<details><summary><strong>[方法論ノート — Layer 3]</strong></summary>'
            "<p><strong>縮約:</strong> Beta-Binomial 経験ベイズ。Prior Beta(α₀,β₀) をモーメント法で母集団から推定。"
            "Posterior mean = (α₀+s)/(α₀+β₀+n)。試行数 n が大きいほど素の成功率に近づき、小さいほど母集団平均に引き寄せられる。<br>"
            "<strong>vs Baseline:</strong> (実際の成功率) / (昇進前ステージのコホート平均昇進率)。"
            "成功率は「昇進した人物が昇進後もさらに上位ステージに進んだ割合」。<br>"
            "<strong>帰属の限界:</strong> 30人の現場で1人が昇進すれば残り29人全員にカウントされる。"
            "役職ペア（監督→演出）への絞り込みや複数作品での継続性要件は未実装。</p>"
            "</details>"
        )
        body += "</div>"

    # Data-driven key findings
    foresight_count = len(foresight)
    promo_count = len(promotions)
    year_span = f"{min(years_computed)}-{max(years_computed)}" if years_computed else "N/A"
    holdout_note = ""
    if holdout and "roc_auc" in holdout:
        fs_auc = holdout["roc_auc"].get("foresight", 0.5)
        bl_auc = holdout["roc_auc"].get("baseline_activity", 0.5)
        if fs_auc > bl_auc + 0.03:
            holdout_note = f"ホールドアウト検証ではROC-AUC {fs_auc:.3f}（活動量ベースライン {bl_auc:.3f}）を上回り、共演パターン信号に付加的情報があることが示された"
        else:
            holdout_note = f"ホールドアウト検証ではROC-AUC {fs_auc:.3f}（活動量ベースライン {bl_auc:.3f}と近接）。共演パターン信号は活動量で大部分説明できる可能性がある"
    body += key_findings([
        f"BiRankは {year_span} の {len(years_computed)} 年間で動的に変化し、"
        "個人のキャリアフェーズに応じたピークと転換が観察される",
        f"{fmt_num(foresight_count)} 人が、後に高BiRankを獲得した人物と彼らの無名時代に共演していた"
        "構造的パターンを持つ（事後的記述。因果解釈には追加検証が必要）",
        holdout_note or f"昇進クレジット追跡対象 {fmt_num(promo_count)} 人について、"
        "キャリアステージ昇進の帰属構造が記録されている",
    ])

    body += significance_section("時系列BiRankで何が分かるか", [
        "BiRankの時系列推移は「いつ、どの時期にネットワーク上の重要性が変化したか」を記述します。"
        "現役で上昇中（rising）の人物は打ち切りにより過小評価される傾向があるため、"
        "Peak BiRankと「現役/確定」ステータスを合わせて参照してください。",
        "共演パターンスコアと昇進クレジットはいずれも共演構造の記述であり、"
        "「目利き能力の証明」や「育成力の証明」として使用する場合は"
        "上記のホールドアウト検証結果と方法論上の限界を参照してください。"
        "活動量・時代効果・役職構成との交絡が未制御です。",
    ])
    body += utilization_guide([
        {"role": "スタジオ人事", "how": "BiRank Evolution（Top 10）でtrajectory=risingかつis_censored=Trueの人物を抽出。現役上昇中＝現時点でのエンゲージメント検討候補。ピーク前の現時点で契約検討するための一次情報として使用"},
        {"role": "リサーチャー", "how": "ホールドアウト検証のROC-AUCを確認し、共演パターン信号が活動量ベースラインを上回るかどうかを確認してから分析に使用する。AUC < 0.6なら共演パターンよりも活動量指標を優先すべき"},
        {"role": "制作担当", "how": "昇進クレジット上位者の「vs Baseline」列を確認。2.0x以上かつ縮約後成功率50%以上が確認できる人物は、同ステージ間の業界平均比較において際立つ共演パターンを持つ"},
        {"role": "若手スタッフ", "how": "昇進クレジット上位者との共演歴を自身のキャリアと照合する際は、因果関係ではなく相関であることを念頭に置く。縮約後成功率と試行数（Promotions列）の両方を確認すること"},
    ])
    body += future_possibilities([
        "役職ペア絞り込み: 「監督→演出」「作監→原画」など指導構造が明確な上下役職ペアのみを昇進エッジとして抽出し、30人共演問題を緩和",
        "傾向スコアマッチング: 年代・役職・活動量でマッチさせた対照群との比較で共演→昇進の因果効果を推定",
        "Discovery-Verification ラグ分布の推定: 共演から「ブレイク確認」までの時間分布を計測し、近年の発見者の系統的過小評価を定量化",
        "時代・ジャンル固定効果の導入: era×genre FEを回帰に追加し、共演パターン信号から時代効果を除去",
    ])

    html = wrap_html(
        "時系列BiRank・共演パターン分析",
        f"時系列BiRank推定・共演パターン分析 — {fmt_num(tp.get('total_persons', 0))}人 / {len(years_computed)}年間",
        body,
        intro_html=report_intro(
            "時系列BiRank・共演パターン分析",
            "BiRankは静的ではなく、キャリアの進行とともに変化します。本レポートでは"
            "各人物のネットワーク中心性の時系列変化を追跡し、後にブレイクした人材との"
            "共演パターンを事後的に記述します。予測的解釈にはホールドアウト検証結果を参照してください。",
            "スタジオ人事、リサーチャー、キャリア研究者",
        ),
        glossary_terms={
            **COMMON_GLOSSARY_TERMS,
            "時系列PageRank": (
                "協業グラフの年次累積スナップショットに対してWarm-start PageRankを繰り返し計算したもの。"
                "厳密な temporal PageRank（時間順序保存）ではなく年次静的PageRankの反復。"
                "キャリアを通じたネットワーク中心性の変化の近似的記述。"
            ),
            "共演パターンスコア (旧称: 先見スコア)": (
                "後に高BiRankとなった人物と、彼らの低BiRank時代に共演していた頻度×強度の事後計算値。"
                "「目利き能力」の証明ではなく共演構造の記述。"
                "予測的解釈にはホールドアウト検証（ROC-AUC）を確認のこと。"
            ),
            "昇進クレジット": (
                "キャリアステージ昇進イベントを、同じ現場にいた最上位役職者に帰属したもの。"
                "直接の指導関係とは区別が必要（共演=指導ではない）。"
                "ランキングはBeta-Binomial縮約後の成功率を使用（素の成功率は試行数が少ない場合に不安定）。"
            ),
            "Beta-Binomial縮約": (
                "試行数が少ない人物の成功率を母集団の事前分布方向に修正する経験ベイズ手法。"
                "Posterior mean = (α₀+successes)/(α₀+β₀+trials)。"
                "試行数が多いほど素の成功率に近づき、少ないほど母集団平均に引き寄せられる。"
            ),
            "右打ち切り (Right Censoring)": (
                "現役で活動継続中の人物は真のピークに未達の可能性があり、"
                "観測済みのPeak BiRankは下限値として解釈すべき状態。"
                "is_censored=Trueの人物はPeak順位が過小評価される傾向がある。"
            ),
        },
    )
    out = REPORTS_DIR / "temporal_foresight.html"
    out.write_text(html, encoding="utf-8")
    print(f"    -> {out}")


# ============================================================
# Report 6: Network Evolution
# ============================================================

def generate_network_evolution_report():
    """ネットワーク進化レポート（強化版: 6チャート）."""
    print("  Generating Network Evolution Report...")
    net_evo = load_json("network_evolution.json")
    if not net_evo:
        return

    body = ""

    years = net_evo.get("years", [])
    snapshots = net_evo.get("snapshots", {})

    if not isinstance(net_evo, dict) or "years" not in net_evo or not years:
        return

    # --- スナップショットデータをリスト化 ---
    sorted_years = sorted(years)
    active_persons = []
    new_persons = []
    cumul_persons = []
    cumul_edges = []
    density_vals = []
    for y in sorted_years:
        snap = snapshots.get(str(y), {})
        active_persons.append(snap.get("active_persons", 0))
        new_persons.append(snap.get("new_persons", 0))
        cumul_persons.append(snap.get("cumulative_persons", 0))
        cumul_edges.append(snap.get("cumulative_edges", 0))
        density_vals.append(snap.get("density", 0))

    body += '<div class="card">'
    body += "<h2>ネットワーク進化サマリー</h2>"
    body += f'<div class="insight-box">{len(sorted_years)} 年間（{min(sorted_years)}-{max(sorted_years)}）のネットワーク位相変化を追跡。'
    body += f' 最終規模: {fmt_num(cumul_persons[-1] if cumul_persons else 0)}人, {fmt_num(cumul_edges[-1] if cumul_edges else 0)}エッジ</div>'
    body += "</div>"

    # --- Chart 1: 年代別アクティブ人数 積み上げ面 ---
    fig1 = go.Figure()
    fig1.add_trace(go.Scatter(
        x=sorted_years, y=active_persons, fill="tozeroy",
        name="アクティブ人数", line=dict(color="#f093fb", width=2),
        hovertemplate="%{x}: %{y:,}人<extra>アクティブ</extra>",
    ))
    fig1.add_trace(go.Scatter(
        x=sorted_years, y=new_persons, fill="tozeroy",
        name="新規参入人数", line=dict(color="#a0d2db", width=1.5),
        hovertemplate="%{x}: %{y:,}人<extra>新規</extra>",
    ))
    fig1.update_layout(title="年代別アクティブ人数推移", xaxis_title="年", yaxis_title="人数")
    body += '<div class="card"><h2>1. 年代別アクティブ人数推移</h2>'
    body += chart_guide("紫=その年にクレジットが1件以上ある人数。水色=その年に初登場した新規人数。")
    body += plotly_div_safe(fig1, "ne_active", 450)
    body += "</div>"

    # --- Chart 2: ネットワーク密度時系列 ---
    fig2 = go.Figure()
    fig2.add_trace(go.Scatter(
        x=sorted_years, y=density_vals, mode="lines+markers",
        line=dict(color="#06D6A0", width=2), marker=dict(size=3),
        name="密度", hovertemplate="%{x}: %{y:.6f}<extra>密度</extra>",
    ))
    fig2.update_layout(title="ネットワーク密度推移", xaxis_title="年", yaxis_title="密度")
    body += '<div class="card"><h2>2. ネットワーク密度推移</h2>'
    body += section_desc("密度=実エッジ数/可能エッジ数。ネットワーク規模が拡大すると密度は自然に低下する傾向があるため、"
                         "密度の上昇は協業の活性化を意味する。")
    body += plotly_div_safe(fig2, "ne_density", 400)
    body += "</div>"

    # --- Chart 3: 巨大連結成分サイズ推移 ---
    fig3 = go.Figure()
    fig3.add_trace(go.Scatter(
        x=sorted_years, y=cumul_persons, mode="lines",
        line=dict(color="#667eea", width=2), name="累積人数",
        hovertemplate="%{x}: %{y:,}人<extra>累積</extra>",
    ))
    fig3.add_trace(go.Scatter(
        x=sorted_years, y=cumul_edges, mode="lines",
        line=dict(color="#fda085", width=2), name="累積エッジ",
        yaxis="y2", hovertemplate="%{x}: %{y:,}エッジ<extra>累積</extra>",
    ))
    fig3.update_layout(
        title="累積人数・エッジ数推移",
        xaxis_title="年", yaxis_title="累積人数", yaxis_type="log",
        yaxis2=dict(title="累積エッジ数", overlaying="y", side="right", type="log"),
    )
    body += '<div class="card"><h2>3. 累積人数・エッジ数推移</h2>'
    body += chart_guide("左軸(青)=累積参加人数。右軸(橙)=累積エッジ数。2軸表示で規模拡大のペースを比較。")
    body += plotly_div_safe(fig3, "ne_cumul", 450)
    body += "</div>"

    # --- Chart 4: 構造変化アノテーション（密度・エッジの最大変化年マーキング）---
    if len(density_vals) >= 3:
        density_changes = [abs(density_vals[i] - density_vals[i-1]) for i in range(1, len(density_vals))]
        edge_changes = [abs(cumul_edges[i] - cumul_edges[i-1]) for i in range(1, len(cumul_edges))]
        fig4 = go.Figure()
        fig4.add_trace(go.Bar(
            x=sorted_years[1:], y=density_changes, name="密度変化量",
            marker_color="#f5576c", opacity=0.7,
            hovertemplate="%{x}: Δ密度=%{y:.6f}<extra></extra>",
        ))
        # 最大変化年をマーキング
        if density_changes:
            max_change_idx = density_changes.index(max(density_changes))
            max_change_year = sorted_years[max_change_idx + 1]
            fig4.add_vline(x=max_change_year, line_dash="dash", line_color="#FFD166",
                           annotation_text=f"最大変化: {max_change_year}",
                           annotation_font_color="#FFD166")
        fig4.update_layout(title="年間密度変化量", xaxis_title="年", yaxis_title="|Δ密度|")
        body += '<div class="card"><h2>4. 構造変化イベント検出</h2>'
        body += section_desc("密度の年間変化量。急激な変化は業界構造の転換点を示唆。"
                             "黄色破線は最大変化年。")
        body += plotly_div_safe(fig4, "ne_change", 400)
        body += "</div>"

    # --- Chart 5: 年間成長率（ノード/エッジ前年比 + 移動平均）---
    if len(cumul_persons) >= 3:
        node_growth = []
        edge_growth = []
        for i in range(1, len(cumul_persons)):
            ng = ((cumul_persons[i] - cumul_persons[i-1]) / max(cumul_persons[i-1], 1)) * 100
            eg = ((cumul_edges[i] - cumul_edges[i-1]) / max(cumul_edges[i-1], 1)) * 100
            node_growth.append(ng)
            edge_growth.append(eg)
        # 5年移動平均
        def moving_avg(vals, window=5):
            result = []
            for i in range(len(vals)):
                start = max(0, i - window + 1)
                result.append(sum(vals[start:i+1]) / (i - start + 1))
            return result
        node_ma = moving_avg(node_growth)
        edge_ma = moving_avg(edge_growth)

        fig5 = go.Figure()
        fig5.add_trace(go.Scatter(
            x=sorted_years[1:], y=node_growth, mode="lines",
            line=dict(color="#a0d2db", width=1), opacity=0.4, name="ノード成長率",
        ))
        fig5.add_trace(go.Scatter(
            x=sorted_years[1:], y=node_ma, mode="lines",
            line=dict(color="#a0d2db", width=2.5), name="ノード成長率(5年MA)",
        ))
        fig5.add_trace(go.Scatter(
            x=sorted_years[1:], y=edge_growth, mode="lines",
            line=dict(color="#fda085", width=1), opacity=0.4, name="エッジ成長率",
        ))
        fig5.add_trace(go.Scatter(
            x=sorted_years[1:], y=edge_ma, mode="lines",
            line=dict(color="#fda085", width=2.5), name="エッジ成長率(5年MA)",
        ))
        fig5.update_layout(title="年間成長率（前年比%）+ 5年移動平均",
                           xaxis_title="年", yaxis_title="成長率(%)")
        body += '<div class="card"><h2>5. 年間成長率推移</h2>'
        body += chart_guide("薄い線=前年比成長率。濃い線=5年移動平均。"
                            "エッジ成長率>ノード成長率なら既存人材間の協業が増加。")
        body += plotly_div_safe(fig5, "ne_growth", 450)
        body += "</div>"

    # Chart 6 (全指標サブプロット) removed — redundant with dedicated charts above.

    # Data-driven key findings
    if years:
        years_span = f"{min(years)}-{max(years)}"
        years_count = len(years)
        years_note = f"{years_span} の {years_count} 年間にわたり"
    else:
        years_note = "複数年間にわたり"
    body += key_findings([
        f"協業ネットワークは{years_note}構造的に変化し続けており、"
        "ノード数・エッジ数ともに増加傾向",
        "ネットワーク密度とクラスタリング係数の推移から、"
        "協業パターンの時代的変遷が読み取れる",
        "連結成分数の変化は業界の「孤立期」と「統合期」を示し、"
        "コラボレーション文化の形成過程が可視化される",
    ])

    body += significance_section("業界構造の時系列変化を追跡", [
        "ネットワーク位相（密度・クラスタリング・連結成分数）の変化は業界の協業文化がどう進化したかを示します。"
        "密度の上昇は協業の活性化、クラスタリング係数の上昇は専門コミュニティの形成・分化を意味します。"
        "これは「業界の健康状態のバイタルサイン」として機能する継続観測指標です。",
        "M&A・スタジオ合併・業界再編が発生した年のネットワーク変化を特定することで、"
        "構造的ショックの影響規模を定量的に評価できます。"
        "また密度の急落や連結成分数の増加は、業界分断の早期兆候として読み取れます。",
    ])
    body += utilization_guide([
        {"role": "スタジオ経営者", "how": "Network Metrics Over Timeチャートの密度グラフで自社が活発に活動していた時期のネットワーク構造を確認し、その時期の制作体制を現在の戦略立案の参考にする"},
        {"role": "M&A担当者", "how": "合併候補スタジオが属するコミュニティのエッジ数推移を確認し、統合後に自社ネットワークのエッジ数がどれだけ増加するかを事前に試算して提携判断の根拠とする"},
        {"role": "業界アナリスト", "how": "ノード数・エッジ数・密度の年次データを業界白書や投資家向けレポートの定量的根拠として引用し、業界全体の成熟度を客観的に示す"},
        {"role": "学術研究者", "how": "クラスタリング係数と密度の長期時系列をネットワーク科学論文の実証データとして活用し、アニメ産業の演化の法則性を分析する"},
    ])
    body += future_possibilities([
        "特定の「転換点年」の同定と要因分析（政策変化・技術革新・主要スタジオ設立閉鎖との対応関係の検証）",
        "ネットワーク構造変化の健康診断レポートとしての年次定期発行（前年比での指標変化を自動解説）",
        "コミュニティ分断の早期検知アラート（密度やエッジ数が急落した時のステークホルダーへの警告）",
        "業界縮小期・拡大期の構造的特徴を学習した予測モデル（次の変曲点タイミングの見通し）",
    ])

    html = wrap_html(
        "ネットワーク構造変化",
        "協業ネットワーク位相の時系列変化",
        body,
        intro_html=report_intro(
            "ネットワーク構造変化",
            "アニメ協業ネットワークは構造的にどう変化してきたのか？ 本レポートでは"
            "主要なグラフ指標 — ノード数・エッジ数・密度・クラスタリング係数・"
            "連結成分 — を数十年の制作期間にわたって追跡します。",
            "ネットワーク研究者、業界アナリスト",
        ),
        glossary_terms={
            **COMMON_GLOSSARY_TERMS,
            "密度 (Density)": (
                "グラフ上の実際のエッジ数と可能なエッジ数の比率。"
                "密度が高いほどネットワーク規模に対して協業接続が多い。"
            ),
            "クラスタリング係数 (Clustering Coefficient)": (
                "ノードがどの程度クラスタを形成する傾向にあるかの指標。"
                "高い値は密接な協業グループの存在を示す。"
            ),
            "連結成分 (Connected Component)": (
                "すべてのノードが何らかのパスで相互到達可能なグループ。"
                "複数の成分は孤立したサブネットワークの存在を意味する。"
            ),
        },
    )
    out = REPORTS_DIR / "network_evolution.html"
    out.write_text(html, encoding="utf-8")
    print(f"    -> {out}")


# ============================================================
# Report 7: Growth & Score Analysis
# ============================================================

def generate_growth_score_report():
    """成長・スコア分析レポート."""
    print("  Generating Growth & Score Report...")
    growth = get_feat_career()
    insights = load_json("insights_report.json")

    body = ""

    if growth:
        trend_summary = growth.get("trend_summary", {})
        total = growth.get("total_persons", 0)

        body += '<div class="card">'
        body += "<h2>Growth Trends Overview</h2>"
        body += '<div class="stats-grid">'
        trend_colors = {"inactive": "#666", "new": "#a0d2db", "rising": "#06D6A0", "declining": "#EF476F", "stable": "#FFD166"}
        for trend, count in sorted(trend_summary.items(), key=lambda x: x[1], reverse=True):
            pct = count / max(total, 1) * 100
            body += f'<div class="stat-card"><div class="value">{fmt_num(count)}</div>'
            body += f'<div class="label">{trend.title()} ({pct:.1f}%)</div></div>'
        body += "</div></div>"

        # Trend horizontal stacked bar
        trend_order_bar = ["rising", "stable", "declining", "new", "inactive"]
        fig = go.Figure()
        for t in trend_order_bar:
            cnt = trend_summary.get(t, 0)
            if cnt > 0:
                pct = cnt / max(total, 1) * 100
                fig.add_trace(go.Bar(
                    x=[cnt], y=["全人物"],
                    name=f"{t.title()} ({pct:.1f}%)",
                    orientation="h",
                    marker_color=trend_colors.get(t, "#888"),
                    text=[f"{t.title()}: {fmt_num(cnt)}"],
                    textposition="inside",
                    hovertemplate=f"{t.title()}: {fmt_num(cnt)} ({pct:.1f}%)<extra></extra>",
                ))
        fig.update_layout(
            barmode="stack",
            title=f"成長トレンド構成比 — {fmt_num(total)}人",
            xaxis_title="人数",
            showlegend=True,
            legend=dict(orientation="h", y=-0.2),
            height=250,
        )
        body += '<div class="card">'
        body += "<h2>Trend Distribution</h2>"
        body += chart_guide(
            "全人物の成長カテゴリ構成比を横積み上げ棒グラフで表示。"
            "Rising=活動増加中、Stable=安定、Declining=活動減少中、"
            "New=最近参入、Inactive=最近のクレジットなし。"
            "各セグメントの幅が人数に比例。"
        )
        body += plotly_div_safe(fig, "trend_bar", 250)
        body += "</div>"

        # Violin: trend category vs total_credits
        persons = growth.get("persons", {})
        trend_credits: dict[str, list[int]] = {}
        for pid, p in persons.items():
            t = p.get("trend", "unknown")
            tc = p.get("total_credits", 0)
            trend_credits.setdefault(t, []).append(tc)

        trend_order = ["rising", "stable", "declining", "new", "inactive"]
        trend_violin_colors = {"rising": "#06D6A0", "stable": "#FFD166", "declining": "#EF476F",
                               "new": "#a0d2db", "inactive": "#666"}
        if trend_credits:
            fig_tv = go.Figure()
            for t in trend_order:
                if t in trend_credits and len(trend_credits[t]) >= 3:
                    fig_tv.add_trace(_violin_raincloud(
                        trend_credits[t],
                        t.title(),
                        trend_violin_colors.get(t, "#888"),
                    ))
            fig_tv.update_layout(
                title="トレンドカテゴリ別 総クレジット数分布 (Raincloud)",
                yaxis_title="総クレジット数",
                yaxis_type="log",
                xaxis_title="トレンドカテゴリ",
                violinmode="overlay",
            )
            body += '<div class="card">'
            body += "<h2>トレンドカテゴリ別 総クレジット数分布</h2>"
            body += chart_guide(
                "Violin plotで各トレンドカテゴリの総クレジット数分布を比較。"
                "Risingなのにクレジット数が少ない＝急成長新人、Stableで多い＝安定ベテラン。"
                "分布の形状と中央値から各カテゴリの特性を把握できます。"
            )
            body += plotly_div_safe(fig_tv, "trend_violin", 500)
            body += "</div>"

        # Time series: yearly rolling trend counts (3-year window)
        # NOTE: Previously this applied each person's FINAL trend retroactively
        # to all years they were active. Now we compute a per-year rolling trend
        # from yearly_credits so 1990 is not filled with "declining" persons
        # who only declined in 2025.
        yearly_trend_counts: dict[int, dict[str, int]] = {}
        for pid, p in persons.items():
            yearly_credits = p.get("yearly_credits", {})
            yc_int = {}
            for yr_str, cnt in yearly_credits.items():
                try:
                    yc_int[int(yr_str)] = cnt
                except (ValueError, TypeError):
                    continue
            if not yc_int:
                continue
            first_yr = min(yc_int)
            for yr in sorted(yc_int):
                if yc_int[yr] <= 0:
                    continue
                yearly_trend_counts.setdefault(yr, {"rising": 0, "stable": 0, "declining": 0, "new": 0})
                # Rolling 3-year window trend classification
                years_since_debut = yr - first_yr
                if years_since_debut <= 2:
                    trend = "new"
                else:
                    recent = sum(yc_int.get(y, 0) for y in range(yr - 1, yr + 1))
                    prior = sum(yc_int.get(y, 0) for y in range(yr - 3, yr - 1))
                    if prior == 0:
                        trend = "new" if recent > 0 else "stable"
                    elif recent > prior * 1.3:
                        trend = "rising"
                    elif recent < prior * 0.5:
                        trend = "declining"
                    else:
                        trend = "stable"
                yearly_trend_counts[yr][trend] += 1

        if yearly_trend_counts:
            sorted_yrs = sorted(yearly_trend_counts.keys())
            # Filter to reasonable range
            sorted_yrs = [yr for yr in sorted_yrs if yr >= 1980]
            area_colors = {"rising": "#06D6A0", "stable": "#FFD166", "declining": "#EF476F",
                           "new": "#a0d2db"}
            fig_ts = go.Figure()
            for t in ["rising", "stable", "declining", "new"]:
                fig_ts.add_trace(go.Scatter(
                    x=sorted_yrs,
                    y=[yearly_trend_counts.get(yr, {}).get(t, 0) for yr in sorted_yrs],
                    name=t.title(),
                    mode="lines",
                    stackgroup="one",
                    line=dict(color=area_colors.get(t, "#888")),
                    hovertemplate="%{x}: " + t.title() + " %{y}人<extra></extra>",
                ))
            fig_ts.update_layout(
                title="年別ローリングトレンド推移（上位200人サンプル・3年窓）",
                xaxis_title="年",
                yaxis_title="人数",
            )
            body += '<div class="card">'
            body += "<h2>年別ローリングトレンド推移（サンプル）</h2>"
            body += caveat_box(
                "growth.jsonは上位200人のみの詳細データを含みます。この時系列は業界全体ではなく"
                "サンプルの推移です。各年のトレンドは3年ローリング窓で分類しており、"
                "最終トレンドの遡及適用ではありません。"
            )
            body += chart_guide(
                "上位200人について、各年ごとに3年窓のローリングトレンドを算出し積み上げ表示。"
                "Rising=直近2年のクレジットが前2年より30%以上増加、"
                "Declining=50%以上減少、Stable=その中間、New=デビュー3年以内。"
            )
            body += plotly_div_safe(fig_ts, "trend_yearly", 450)
            body += "</div>"

        # NOTE: Activity vs Quality scatter removed — it used recent_avg_anime_score
        # and career_avg_anime_score (viewer ratings), violating the no-viewer-rating
        # scoring principle. See CLAUDE.md "Prohibited Data Sources".

        # ---- K-Means クラスタリング: キャリア軌跡タイプ ----
        if len(persons) >= 5:
            import numpy as _np_gr
            from sklearn.cluster import KMeans as _KMeans_gr
            from sklearn.preprocessing import StandardScaler as _SC_gr

            GR_COLORS = ["#f093fb", "#06D6A0", "#fda085", "#a0d2db", "#FFD166", "#EF476F"]
            gr_persons_list = []
            for pid, p in persons.items():
                yc = p.get("yearly_credits", {})
                debut_yr = float(min(int(k) for k in yc)) if yc else 0.0
                ty = float(p.get("total_years", 0) or 0)
                tc = float(p.get("total_credits", 0) or 0)
                gr_persons_list.append({
                    "pid": pid,
                    "name": p.get("name", pid),
                    "trend": p.get("trend", "unknown"),
                    "total_credits": tc,
                    "credits_per_year": tc / max(ty, 1),
                    "career_span": float(p.get("career_span", 0) or 0),
                    "active_ratio": float(p.get("activity_ratio", 0) or 0),
                    "debut_year": debut_yr,
                })

            GR_FEAT_COLS = [
                "total_credits", "credits_per_year", "career_span",
                "active_ratio", "debut_year",
            ]
            GR_FEAT_JP = {
                "total_credits": "総クレジット", "credits_per_year": "年間クレジット",
                "career_span": "キャリア期間", "active_ratio": "活動率",
                "debut_year": "デビュー年",
            }
            Xgr = _np_gr.array([[p[f] for f in GR_FEAT_COLS] for p in gr_persons_list], dtype=float)
            sc_gr = _SC_gr()
            Xgr_s = sc_gr.fit_transform(Xgr)
            k_gr = min(5, len(gr_persons_list))
            km_gr = _KMeans_gr(n_clusters=k_gr, n_init=20, random_state=42)
            gr_labels = km_gr.fit_predict(Xgr_s)
            centers_gr = sc_gr.inverse_transform(km_gr.cluster_centers_)
            fidx_gr = {f: i for i, f in enumerate(GR_FEAT_COLS)}

            # 動的クラスタ命名
            gr_cluster_names = _name_clusters_by_rank(
                centers_gr,
                [
                    (fidx_gr["total_credits"],   ["多作ベテラン", "中堅", "新人少作"]),
                    (fidx_gr["credits_per_year"], ["高密度", "中密度", "低密度"]),
                    (fidx_gr["active_ratio"],     ["高活動", "中活動", "低活動"]),
                    (fidx_gr["debut_year"],        ["新世代", "中堅世代", "ベテラン世代"]),
                ],
            )

            for i, p in enumerate(gr_persons_list):
                p["gr_cluster"] = int(gr_labels[i])
                p["gr_cluster_name"] = gr_cluster_names[int(gr_labels[i])]

            gr_cluster_groups: dict[int, list[dict]] = {}
            for p in gr_persons_list:
                gr_cluster_groups.setdefault(p["gr_cluster"], []).append(p)

            body += '<div class="card">'
            body += f"<h2>キャリア軌跡 K-Means クラスタリング（{k_gr}クラスタ）</h2>"
            body += section_desc(
                "総クレジット数・年間クレジット・キャリア期間・活動率・デビュー年の"
                f"5特徴量で全スタッフを{k_gr}クラスタに自動分類。"
                "「多作ベテラン×高密度」「新世代の急成長株」等のキャリアタイプを識別します。"
            )

            # Scatter: credits_per_year vs active_ratio colored by cluster
            fig_gr_sc = go.Figure()
            for cid in sorted(gr_cluster_groups.keys()):
                mems_gr = gr_cluster_groups[cid]
                fig_gr_sc.add_trace(go.Scattergl(
                    x=[m["credits_per_year"] for m in mems_gr],
                    y=[m["active_ratio"] for m in mems_gr],
                    mode="markers",
                    name=gr_cluster_names[cid],
                    marker=dict(
                        size=5,
                        color=GR_COLORS[cid % len(GR_COLORS)],
                        opacity=0.6,
                    ),
                    text=[m["name"] for m in mems_gr],
                    hovertemplate="%{text}<br>年間クレジット: %{x:.2f}<br>活動率: %{y:.2f}<extra></extra>",
                ))
            fig_gr_sc.update_layout(
                title="キャリアクラスタ散布図（年間クレジット × 活動率）",
                xaxis_title="年間クレジット数", yaxis_title="活動率",
            )
            body += chart_guide(
                "各点は1人。色＝クラスタ。右上＝年間クレジットも活動率も高い（活発な多作型）、"
                "左下＝低活動。クラスタが集中する位置でキャリアタイプのパターンが見えます。"
            )
            body += plotly_div_safe(fig_gr_sc, "growth_cluster_scatter", 520)

            # Cluster profile heatmap (z-score)
            z_gr = km_gr.cluster_centers_  # already z-scored
            fig_gr_hmap = go.Figure(go.Heatmap(
                z=[[z_gr[cid, fidx_gr[f]] for f in GR_FEAT_COLS] for cid in range(k_gr)],
                x=[GR_FEAT_JP.get(f, f) for f in GR_FEAT_COLS],
                y=[gr_cluster_names[c] for c in range(k_gr)],
                colorscale="RdBu", zmid=0,
                colorbar=dict(title="z-score"),
                hovertemplate="クラスタ: %{y}<br>特徴: %{x}<br>z-score: %{z:.2f}<extra></extra>",
            ))
            fig_gr_hmap.update_layout(
                title="キャリアクラスタプロファイル Heatmap（z-score）",
                xaxis_tickangle=-25,
            )
            body += chart_guide("赤＝そのクラスタが平均より高い特徴、青＝低い特徴。クラスタの特徴が一目で分かります。")
            body += plotly_div_safe(fig_gr_hmap, "growth_cluster_heatmap", 450)

            # Violin: total_credits per cluster
            fig_gr_viol = go.Figure()
            for cid in sorted(gr_cluster_groups.keys()):
                mems_gr = gr_cluster_groups[cid]
                tc_vals = [m["total_credits"] for m in mems_gr]
                if tc_vals:
                    fig_gr_viol.add_trace(_violin_raincloud(
                        tc_vals, gr_cluster_names[cid], GR_COLORS[cid % len(GR_COLORS)],
                    ))
            fig_gr_viol.update_layout(
                title="クラスタ別 総クレジット数分布 (Raincloud)",
                yaxis_title="総クレジット数",
                violinmode="overlay",
            )
            body += chart_guide("各クラスタの総クレジット数分布。多作ベテランvs新人少作の差が見えます。")
            body += plotly_div_safe(fig_gr_viol, "growth_cluster_violin", 450)

            # Stacked bar: cluster × trend
            fig_gr_trend = go.Figure()
            trend_colors_gr = {"rising": "#06D6A0", "stable": "#FFD166", "declining": "#EF476F",
                               "new": "#a0d2db", "inactive": "#666"}
            trend_order_gr = ["rising", "stable", "declining", "new", "inactive"]
            for t in trend_order_gr:
                t_counts = [
                    sum(1 for m in gr_cluster_groups.get(c, []) if m["trend"] == t)
                    for c in range(k_gr)
                ]
                if any(x > 0 for x in t_counts):
                    fig_gr_trend.add_trace(go.Bar(
                        name=t.title(),
                        x=[gr_cluster_names[c] for c in range(k_gr)],
                        y=t_counts,
                        marker_color=trend_colors_gr.get(t, "#888"),
                    ))
            fig_gr_trend.update_layout(
                title="クラスタ × トレンドカテゴリ（人数）",
                barmode="stack", xaxis_tickangle=-20, yaxis_title="人数",
            )
            body += chart_guide("K-Meansクラスタとトレンド分類の対応。各クラスタにどのトレンドが多いかを確認。")
            body += plotly_div_safe(fig_gr_trend, "growth_cluster_trend_bar", 420)
            body += "</div>"

        # Bar+Line: Career Year Retention Curve
        scores_for_retention = get_feat_person_scores()
        if scores_for_retention:
            active_years_list = [
                p.get("career", {}).get("active_years", 0)
                for p in scores_for_retention
                if p.get("career", {}).get("active_years", 0) > 0
            ]
            if active_years_list:
                total_people_ret = len(active_years_list)
                max_year_ret = min(max(active_years_list), 30)
                years_range_ret = list(range(1, max_year_ret + 1))
                surviving = [sum(1 for y in active_years_list if y >= yr) for yr in years_range_ret]
                survival_rate = [s / total_people_ret * 100 for s in surviving]
                fig_ret = make_subplots(specs=[[{"secondary_y": True}]])
                fig_ret.add_trace(
                    go.Bar(
                        x=years_range_ret, y=surviving, name="人数",
                        marker_color="rgba(240,147,251,0.4)",
                        hovertemplate="%{x}年以上: %{y}人<extra></extra>",
                    ),
                    secondary_y=False,
                )
                fig_ret.add_trace(
                    go.Scatter(
                        x=years_range_ret, y=survival_rate, name="生存率 (%)",
                        mode="lines+markers",
                        line=dict(color="#06D6A0", width=3),
                        marker=dict(size=5),
                        hovertemplate="%{x}年以上: %{y:.1f}%<extra></extra>",
                    ),
                    secondary_y=True,
                )
                fig_ret.update_layout(title="キャリア年数別 生存率曲線（Retention Curve）")
                fig_ret.update_yaxes(title_text="人数", secondary_y=False)
                fig_ret.update_yaxes(title_text="生存率 (%)", secondary_y=True)
                body += '<div class="card">'
                body += "<h2>キャリア生存率曲線</h2>"
                body += caveat_box(
                    "単純な断面集計でありKaplan-Meier法の打ち切り処理は未実施です。"
                    "2020年以降にデビューした人物の長期生存率は観測期間不足で過小推定されます。"
                    "コホート別に比較する場合、観測打ち切りの影響に注意してください。"
                )
                body += chart_guide(
                    "棒グラフ（左Y軸）: その年数以上活動している人数。"
                    "折れ線（右Y軸）: 全体に対する生存率%。"
                    "急激な減少は離脱が多い時期を示し、キャリア持続の障壁を示唆します。"
                )
                body += plotly_div_safe(fig_ret, "retention_curve", 500)
                body += "</div>"

        # Sample rising stars
        persons = growth.get("persons", {})
        rising = [(pid, p) for pid, p in persons.items() if p.get("trend") == "rising"]
        rising.sort(key=lambda x: x[1].get("total_credits", 0), reverse=True)

        if rising:
            body += '<div class="card">'
            body += f"<h2>Rising Stars ({len(rising)} persons)</h2>"
            body += section_desc(
                "「上昇中」に分類されたプロフェッショナル — クレジット数と活動が増加中。"
                "総クレジット数順にソートし、最も活発な人材を強調します。"
            )
            body += "<table><thead><tr>"
            body += "<th>#</th><th>Person</th><th>Total Credits</th><th>Career Span</th><th>Activity Ratio</th>"
            body += "</tr></thead><tbody>"
            for i, (pid, p) in enumerate(rising[:30], 1):
                g_name = p.get("name", pid)
                body += f"<tr><td>{i}</td><td>{g_name}</td><td>{p.get('total_credits', 0)}</td>"
                body += f"<td>{p.get('career_span', 0)} yrs</td>"
                body += f"<td>{p.get('activity_ratio', 0):.2f}</td></tr>"
            body += "</tbody></table></div>"

    # Insights: undervaluation alerts
    if insights:
        alerts = insights.get("undervaluation_alerts", [])
        if alerts:
            body += '<div class="card">'
            body += f"<h2>Undervaluation Alerts ({len(alerts)} persons)</h2>"
            body += '<div class="insight-box"><strong>Warning:</strong> These persons may be undervalued based on bias-corrected analysis. '
            body += "Studio size bias correction reveals hidden contributions.</div>"
            body += "<table><thead><tr>"
            body += "<th>#</th><th>Person</th><th>Current IV Score</th><th>Debiased BiRank</th><th>Gap</th><th>Category</th>"
            body += "</tr></thead><tbody>"
            for i, a in enumerate(alerts[:20], 1):
                gap = a.get("authority_gap", 0)
                badge = "badge-high" if gap >= 5 else "badge-mid" if gap >= 2 else "badge-low"
                name = a.get("name", a.get("person_id", ""))
                pid_a = a.get("person_id", "")
                body += f"<tr><td>{i}</td><td>{person_link(name, pid_a)}</td>"
                body += f"<td>{a.get('current_composite', 0):.2f}</td>"
                body += f"<td>{a.get('debiased_authority', 0):.2f}</td>"
                body += f'<td><span class="badge {badge}">+{gap:.2f}</span></td>'
                body += f"<td>{a.get('category', '')}</td></tr>"
            body += "</tbody></table></div>"

        # PageRank analysis
        pa = insights.get("pagerank_analysis", {})
        if pa:
            body += '<div class="card">'
            body += "<h2>PageRank Analysis</h2>"
            body += '<div class="stats-grid">'
            for label, val in [
                ("Top 1% Share", f"{pa.get('top_percentile_share', 0):.1f}%"),
                ("Concentration Ratio", f"{pa.get('concentration_ratio', 0):.3f}"),
                ("Avg Score", f"{pa.get('avg_score', 0):.2f}"),
                ("Median Score", f"{pa.get('median_score', 0):.2f}"),
            ]:
                body += f'<div class="stat-card"><div class="value">{val}</div><div class="label">{label}</div></div>'
            body += "</div>"
            body += f'<div class="insight-box"><strong>Score concentration:</strong> The top 1% of persons hold {pa.get("top_percentile_share", 0):.1f}% of total BiRank. '
            body += f'Average score is {pa.get("avg_score", 0):.2f}, median is {pa.get("median_score", 0):.2f} — '
            body += "indicating a highly skewed distribution typical of scale-free networks.</div>"
            body += "</div>"

    # Data-driven key findings
    growth_total = growth.get("total_persons", 0) if growth else 0
    rising_count = trend_summary.get("rising", 0) if growth else 0
    rising_pct = rising_count / max(growth_total, 1) * 100 if growth else 0
    alerts_count = len(insights.get("undervaluation_alerts", [])) if insights else 0
    body += key_findings([
        f"全 {fmt_num(growth_total)} 人のうち「上昇中」は {fmt_num(rising_count)} 人"
        f"（{rising_pct:.1f}%）— クレジット数が加速的に増加しており、将来の主力候補群",
        f"バイアス補正後の分析により {fmt_num(alerts_count)} 人の過小評価候補が特定され、"
        "適正報酬より低く評価されている可能性がある",
        "スコア集中度は上位1%に偏っており、スケールフリーネットワーク特有の分布を示す",
    ])

    body += significance_section("過小評価された人材の発見と報酬格差の是正", [
        "成長トレンド分析は「現在の評価」だけでなく「将来の価値」を示します。"
        "上昇中の人材を早期に特定することで、報酬格差が拡大する前に公正な契約交渉が可能になります。"
        "スコア分布のべき乗則は少数の人材が業界価値の大半を創出していることを示しており、"
        "このロングテール領域に埋もれた人材を見逃さないことがスタジオの競争優位につながります。",
        "バイアス補正過小評価アラートは、スタジオ所属・役職・キャリアステージによって"
        "不当に低く評価されてきた具体的な人物を特定します。"
        "これはアニメ業界の慢性的な報酬問題に対する、感情ではなくデータに基づくアプローチです。",
    ])
    body += utilization_guide([
        {"role": "スタジオ人事", "how": "Rising Stars一覧でactivity_ratioが高くtotal_creditsが増加中の人物を抽出し、現在の報酬が低い段階で長期契約を提示して競合スタジオより先に確保する"},
        {"role": "アニメーター本人", "how": "Undervaluation Alertsで自分の名前を確認し、debiased_authority（バイアス補正後）がcurrent_compositeより高ければその差（gap列）を具体的な報酬引き上げ根拠として交渉書類に記載する"},
        {"role": "エージェント・代理人", "how": "クライアントのgap値（バイアス補正前後の差）と業界パーセンタイルを組み合わせて「現在の報酬が業界水準より○%低い」と定量化し、契約更新交渉で提示する"},
        {"role": "投資家", "how": "Rising Stars一覧でtotal_creditsとactivity_ratioが急増中の人物が参加する直近作品を特定し、クラウドファンディングや出資の優先候補として見極める"},
    ])
    body += future_possibilities([
        "「過小評価ランキング」の定期公開による業界全体への報酬是正圧力の醸成（匿名化した集計データとして）",
        "成長トレンドが止まった人材へのリスキリング提案（活動量が3期連続減少した時のスキルアップ支援の介入指標）",
        "成長スコアと実際の報酬データを統合した「公正報酬推計ツール」（業界水準との乖離を個人ごとに算出）",
        "証券類似の「ライジングスター指数」として定期配信し、コンテンツ投資判断のリファレンス指標化",
    ])

    html = wrap_html(
        "成長トレンド・スコア分析",
        "成長トレンドとスコア分析",
        body,
        intro_html=report_intro(
            "成長・スコア分析",
            "誰が上昇中で、誰が衰退中で、誰が過小評価されているのか？ 本レポートでは"
            "全プロフェッショナルを成長軌道で分類し、キャリアが加速中のライジングスターを"
            "強調し、バイアス補正PageRank分析に基づく過小評価の可能性を検出します。",
            "タレントスカウト、業界アナリスト、スタジオ人事",
        ),
        glossary_terms={
            **COMMON_GLOSSARY_TERMS,
            "上昇中 (Rising)": "直近年のクレジット活動が増加傾向にある成長トレンド。",
            "衰退中 (Declining)": "クレジット活動が減少傾向にある成長トレンド。",
            "安定 (Stable)": "直近年にわたって一貫した活動レベル。",
            "非活動 (Inactive)": "直近の分析期間にクレジット記録がない状態。",
            "集中度 (Concentration Ratio)": (
                "上位パーセンタイルが保持する総BiRank量の割合。"
                "高い集中度はスケールフリーネットワークの典型。"
            ),
        },
    )
    out = REPORTS_DIR / "growth_scores.html"
    out.write_text(html, encoding="utf-8")
    print(f"    -> {out}")


