                for g in gs[:3]:
                    d = genre_metrics[g][fmt]
                    d['cred_per_hr'].append(cred / total_hr)
                    d['pers_per_hr'].append(pers / total_hr)
                    d['cred_per_cour'].append(cred / cour_count)
